// cards.js — PharmRevise card data
// Schema: { t, top, mod, q, a, hint, tags }
// t = card title, top = topic, mod = module, q = question, a = answer, hint = memory aid, tags = array for filtering

const CARD_DATA = [
// ── CV & HAEMATOLOGY ──────────────────────────────────────
{t:"Anaemia classification",top:"Anaemias",mod:"CV & Haem",q:"What are the 3 MCV-based anaemia categories and an example of each?",a:"Microcytic (<80 fL): iron deficiency, thalassaemia.\nNormocytic (80–100 fL): aplastic, sickle cell, G6PD.\nMacrocytic (>100 fL): megaloblastic (B12/folate).",hint:"Small-Normal-Big. Iron=small; B12/folate=big.",tags:["anaemia","haematology","MCV"]},
{t:"Iron deficiency – Hb thresholds",top:"Anaemias",mod:"CV & Haem",q:"Define anaemia by Hb for adult males, non-pregnant women, and pregnant women.",a:"Men >15 yrs: <130 g/L.\nNon-pregnant women >15 yrs: <120 g/L.\nPregnant: <110 g/L.\nPostpartum: <100 g/L.",hint:"13-12-11 rule.",tags:["anaemia","iron","thresholds"]},
{t:"Oral iron – counselling",top:"Anaemias",mod:"CV & Haem",q:"How should oral iron be taken and what are the main side-effects?",a:"Empty stomach for best absorption (with food if GI SEs). Take with Vit C. SEs: diarrhoea, constipation, nausea, black tarry stools. Toxicity: deferoxamine.",hint:"Black stools = expected. Warn the patient.",tags:["iron","counselling","side-effects"]},
{t:"Iron – drug interactions",top:"Anaemias",mod:"CV & Haem",q:"Name drugs with reduced absorption when taken with iron and required separation times.",a:"Levothyroxine ≥4 hrs. Quinolones ≥4 hrs. Tetracyclines 2–3 hrs. Risedronate ≥2 hrs.\nAntacids: iron 2 hrs before or 1 hr after.",hint:"LQT-R spacing rule.",tags:["iron","interactions","absorption"]},
{t:"Parenteral iron – MHRA warnings",top:"Anaemias",mod:"CV & Haem",q:"What are the two key MHRA warnings for IV iron?",a:"1. Anaphylaxis – trained staff + resuscitation; monitor ≥30 min.\n2. Ferric carboxymaltose → hypophosphataemia → osteomalacia/fractures.",hint:"Anaphylaxis + phosphate – two separate warnings.",tags:["iron","MHRA","IV","anaphylaxis"]},
{t:"B12 deficiency – treatment",top:"Anaemias",mod:"CV & Haem",q:"How is B12 deficiency treated with vs without neurological involvement?",a:"With neuro: IM hydroxocobalamin 1 mg alt days → 1 mg every 2 months.\nWithout neuro: oral cyanocobalamin 500–1000 mcg/day OR IM hydroxocobalamin 1 mg TDS 2 wks → every 2–3 months.",hint:"Neuro = more aggressive IM regime.",tags:["B12","anaemia","neuro"]},
{t:"Folic acid – pregnancy doses",top:"Anaemias",mod:"CV & Haem",q:"What are the two folic acid doses in pregnancy?",a:"400 mcg daily: routine (before conception → wk 12).\n5 mg daily: high NTD risk (sickle cell, epileptics, obesity, smoking, diabetes, antimalarials).",hint:"400 normal, 5000 high-risk.",tags:["folate","pregnancy","NTD"]},
{t:"G6PD – drugs to avoid",top:"Anaemias",mod:"CV & Haem",q:"Name drug classes avoided in G6PD deficiency.",a:"Antibiotics: dapsone, nitrofurantoin, sulphonamides, quinolones.\nAntimalarials: primaquine, chloroquine, hydroxychloroquine.\nOthers: aspirin, rasburicase, methylene blue.",hint:"These cause haemolysis in G6PD deficiency.",tags:["G6PD","haemolysis","drug-avoidance"]},
{t:"ACS – ECG & troponin differentiation",top:"ACS",mod:"CV & Haem",q:"How do ECG and troponin differentiate STEMI, NSTEMI, and unstable angina?",a:"STEMI: ST elevation + raised troponin.\nNSTEMI: no ST elevation + raised troponin.\nUnstable angina: no ST elevation + normal troponin.",hint:"Troponin splits NSTEMI from UA; ST splits STEMI from both.",tags:["ACS","STEMI","troponin","ECG"]},
{t:"ACS – initial management",top:"ACS",mod:"CV & Haem",q:"What is the initial management of confirmed ACS?",a:"Aspirin 300 mg loading. GTN ± IV morphine. O2 only if SpO2 <94%. Monitor glucose. NSTEMI/UA: fondaparinux if no high bleed risk.",hint:"Aspirin first, O2 only when needed.",tags:["ACS","acute","aspirin","oxygen"]},
{t:"ACS – secondary prevention",top:"ACS",mod:"CV & Haem",q:"Name the 5 drug classes in ACS secondary prevention.",a:"ACEi (ARB if intolerant), aspirin lifelong + P2Y12 ×12 months, beta-blocker, atorvastatin 80 mg.",hint:"DABS-A mnemonic.",tags:["ACS","secondary-prevention","antiplatelet","statin"]},
{t:"STEMI – antiplatelet choice",top:"ACS",mod:"CV & Haem",q:"Which P2Y12 agent is used with STEMI PCI and when is clopidogrel used instead?",a:"Prasugrel: preferred if not on oral anticoagulant.\nClopidogrel: use if already on oral anticoagulant.",hint:"OAC on board → clopidogrel.",tags:["STEMI","antiplatelet","prasugrel","clopidogrel"]},
{t:"AF – rate vs rhythm timing",top:"Arrhythmias",mod:"CV & Haem",q:"When is rate control preferred over rhythm control in AF?",a:"Onset <48 hrs: either. Onset >48 hrs: rate control. Haemodynamic instability: emergency cardioversion immediately.",hint:">48 hrs = potential clot → rate first.",tags:["AF","arrhythmia","rate-control","rhythm"]},
{t:"Amiodarone monitoring",top:"Arrhythmias",mod:"CV & Haem",q:"What monitoring is required for amiodarone?",a:"TFTs, LFTs, electrolytes: before + every 6 months.\nCXR: before only.\nECG: before + every 12 months.\nEye exam: annually.",hint:"TFTs/LFTs = 6-monthly; ECG/eyes = yearly.",tags:["amiodarone","monitoring","thyroid","LFT"]},
{t:"Amiodarone – side-effects",top:"Arrhythmias",mod:"CV & Haem",q:"Name 3 major organ toxicities of amiodarone.",a:"Pulmonary toxicity (SOB, non-productive cough).\nThyroid dysfunction (hypo or hyper).\nHepatotoxicity (stop if cirrhosis/hepatitis/jaundice).",hint:"Lung, Thyroid, Liver.",tags:["amiodarone","toxicity","lung","thyroid","liver"]},
{t:"Torsade de Pointes – management",top:"Arrhythmias",mod:"CV & Haem",q:"What causes TdP and how is it treated?",a:"QT prolongation → ventricular arrhythmia. Causes: amiodarone, sotalol, macrolides, haloperidol, SSRIs, TCAs, antifungals, hypokalaemia, bradycardia.\nTreatment: IV magnesium sulphate.",hint:"Mag fixes the spark. IV MgSO4.",tags:["TdP","QT","magnesium","arrhythmia"]},
{t:"Digoxin – toxicity signs",top:"Arrhythmias",mod:"CV & Haem",q:"What is the therapeutic range for digoxin and classic toxicity signs?",a:"0.7–2.0 ng/mL. Toxicity from 1.5–3.0 ng/mL.\nSigns: SA/AV block, bradycardia, D+V, yellow/blurred vision, confusion.\nAntidote: digoxin-specific antibody. Sample 6–12 hrs post-dose.",hint:"Yellow vision = classic exam answer for digoxin toxicity.",tags:["digoxin","toxicity","yellow-vision","antidote"]},
{t:"Warfarin – INR targets",top:"Blood Thinners",mod:"CV & Haem",q:"What INR is targeted for standard vs mechanical valve indications?",a:"INR 2.5: VTEs, AF, cardioversion, MI, cardiomyopathy.\nINR 3.5: recurrent VTEs or mechanical heart valves.",hint:"Valves need higher INR (3.5).",tags:["warfarin","INR","anticoagulation"]},
{t:"Warfarin – bleeding management",top:"Blood Thinners",mod:"CV & Haem",q:"How is warfarin over-anticoagulation managed at different INR levels?",a:"Major bleed: stop + IV phytomenadione + dried prothrombin complex.\nINR >8 + minor bleed: stop + IV phytomenadione.\nINR >8, no bleed: stop + oral phytomenadione.\nINR 5–8 + minor bleed: stop + IV phytomenadione.\nINR 5–8, no bleed: withhold 1–2 doses.",hint:"IV vs oral phytomenadione = is there active bleeding?",tags:["warfarin","bleeding","phytomenadione","reversal"]},
{t:"Warfarin – key interactions",top:"Blood Thinners",mod:"CV & Haem",q:"Name 4 important warfarin interactions that increase INR.",a:"Tramadol (MHRA), miconazole/Daktarin gel (MHRA), cranberry juice, CYP450 inhibitors.\nVitamin K-rich foods (leafy greens) reduce efficacy.",hint:"Tramadol + Miconazole are MHRA-flagged surprises.",tags:["warfarin","interactions","MHRA","INR"]},
{t:"DOACs – Xa vs thrombin + antidotes",top:"Blood Thinners",mod:"CV & Haem",q:"Which DOACs inhibit factor Xa vs thrombin? Antidote for each?",a:"Factor Xa: apixaban, edoxaban, rivaroxaban → andexanet alfa.\nThrombin: dabigatran → idarucizumab.",hint:"A-E-R = anti-Xa. Dabigatran = direct thrombin.",tags:["DOAC","anticoagulation","antidote","Xa","thrombin"]},
{t:"Apixaban – VTE dosing",top:"Blood Thinners",mod:"CV & Haem",q:"What is the apixaban dose for VTE treatment vs prophylaxis?",a:"Treatment: 10 mg BD ×7 days → 5 mg BD.\nProphylaxis post-surgery: 2.5 mg BD.\nStroke prevention AF: 5 mg BD (reduce to 2.5 mg BD if ≥2 of: age ≥80, weight ≤60 kg, creatinine ≥133).",hint:"10-5-2.5 staircase.",tags:["apixaban","VTE","dosing","AF"]},
{t:"Rivaroxaban – food requirement",top:"Blood Thinners",mod:"CV & Haem",q:"What is the critical counselling point unique to rivaroxaban?",a:"Must be taken WITH food (15 mg and 20 mg doses) for adequate absorption.",hint:"Rivaroxaban = takes food. Others don't need food.",tags:["rivaroxaban","counselling","food","absorption"]},
{t:"Clopidogrel – PPI interaction",top:"Blood Thinners",mod:"CV & Haem",q:"Which PPIs interact with clopidogrel and what is the alternative?",a:"Omeprazole and esomeprazole inhibit CYP2C19 (activates clopidogrel) → reduced effect.\nUse lansoprazole instead.",hint:"Omeprazole Off, Lansoprazole On.",tags:["clopidogrel","PPI","CYP2C19","interaction"]},
{t:"LMWH vs UFH",top:"Blood Thinners",mod:"CV & Haem",q:"What are 3 advantages of LMWH over unfractionated heparin?",a:"Lower HIT risk. Longer duration of action. Preferred in pregnancy.\nReversal: protamine sulphate for both. UFH: monitor APTT.",hint:"LMWH = longer, safer, pregnancy-friendly.",tags:["LMWH","heparin","HIT","pregnancy"]},
{t:"Aspirin – Reye's syndrome",top:"Blood Thinners",mod:"CV & Haem",q:"Why is aspirin avoided in under-16s?",a:"Risk of Reye's syndrome – rare but serious liver and brain damage. Also CI in hypersensitivity to aspirin, salicylates, or NSAIDs.",hint:"Reye's = aspirin + viral illness in children.",tags:["aspirin","Reye","paediatric","contraindication"]},
{t:"Heart failure – first-line drugs",top:"Heart Failure",mod:"CV & Haem",q:"What are the 4 first-line classes for HFrEF?",a:"Beta-blocker (bisoprolol/carvedilol/nebivolol), ACEi, MRA (spironolactone/eplerenone), SGLT-2i (dapagliflozin/empagliflozin).\nMnemonic: BAMS.",hint:"BAMS: Beta-blocker, ACEi, MRA, SGLT-2i.",tags:["heart-failure","HFrEF","BAMS","SGLT2"]},
{t:"Heart failure – ARNi indication",top:"Heart Failure",mod:"CV & Haem",q:"When is sacubitril/valsartan used in heart failure?",a:"When all 4 first-line drugs at maximum tolerated dose insufficient, OR when ACEi not suitable. Switch ACEi to sacubitril/valsartan (only licensed ARNi in UK). Never combine with ACEi.",hint:"ARNi replaces ACEi. Never use both together – angioedema.",tags:["heart-failure","ARNi","sacubitril","valsartan"]},
{t:"Hypertension – step therapy",top:"Hypertension",mod:"CV & Haem",q:"Outline step-wise antihypertensive treatment.",a:"Step 1: <55/non-Afro-Carib → ACEi/ARB; >55/Afro-Carib → CCB.\nStep 2: ACEi/ARB + CCB.\nStep 3: + thiazide-like diuretic.\nStep 4: + spironolactone or alpha/beta-blocker.",hint:"A then C then D.",tags:["hypertension","ACEi","CCB","steps"]},
{t:"ACEi side-effects – CHHAReD",top:"Hypertension",mod:"CV & Haem",q:"What are the ACE inhibitor side-effects? Use the mnemonic.",a:"Cough, Hyperkalaemia, Hepatic failure, Angioedema, Renal impairment, Dizziness.\nMnemonic: CHHAReD.",hint:"Cough → ARB. Angioedema → STOP permanently.",tags:["ACEi","side-effects","CHHAReD","angioedema"]},
{t:"Beta-blockers – cardioselective mnemonic",top:"Hypertension",mod:"CV & Haem",q:"Name 5 cardioselective beta-blockers and why selectivity matters.",a:"Bisoprolol, Atenolol, Metoprolol, Acebutolol, Nebivolol.\nMnemonic: BAtMAN.\nCardio-selective = less bronchospasm risk.",hint:"BAtMAN = Bisoprolol, Atenolol, Metoprolol, Acebutolol, Nebivolol.",tags:["beta-blocker","cardioselective","BAtMAN","bronchospasm"]},
{t:"Hypertension in pregnancy",top:"Hypertension",mod:"CV & Haem",q:"What are first, second, and third line antihypertensives in pregnancy?",a:"1st: Labetalol. 2nd: Nifedipine. 3rd: Methyldopa.\nTarget: <135/85 mmHg.\nPre-eclampsia (new onset >140/90): aspirin from week 12 until birth.",hint:"L-N-M in pregnancy.",tags:["hypertension","pregnancy","labetalol","pre-eclampsia"]},
{t:"Statins – monitoring",top:"Hyperlipidaemia",mod:"CV & Haem",q:"What monitoring is required before and after starting a statin?",a:"Before: lipid profile, TFTs, renal function.\nLFTs at 0, 3, 12 months; stop if >3× ULN.\nCK: measure if prior muscle symptoms; >5× ULN → don't initiate.",hint:"LFTs 0-3-12; CK only if symptomatic.",tags:["statin","monitoring","LFT","CK"]},
{t:"Statins – side-effects",top:"Hyperlipidaemia",mod:"CV & Haem",q:"Name 3 important adverse effects of statins.",a:"Myopathy/rhabdomyolysis (check CK).\nInterstitial lung disease (dyspnoea, cough, weight loss).\nTeratogenic – stop 3 months before conception.",hint:"MRT – Myopathy, Respiratory (ILD), Teratogenic.",tags:["statin","myopathy","rhabdomyolysis","teratogen"]},
{t:"Statins – max doses with interactions",top:"Hyperlipidaemia",mod:"CV & Haem",q:"What is the maximum simvastatin dose when co-prescribed with amlodipine, amiodarone, or diltiazem?",a:"Simvastatin max 20 mg with: amlodipine, amiodarone, diltiazem/verapamil.\nSimvastatin max 10 mg with fibrates (not fenofibrate).\nAtorvastatin max 10 mg with ciclosporin.",hint:"These inhibit CYP3A4 → ↑statin → rhabdomyolysis risk.",tags:["simvastatin","CYP3A4","dose","rhabdomyolysis"]},
{t:"VTE – first-line treatment",top:"VTEs",mod:"CV & Haem",q:"What are first-line anticoagulants for confirmed DVT or PE?",a:"Apixaban or rivaroxaban (no bridging needed).\nAlternative: LMWH ≥5 days then dabigatran/edoxaban, or LMWH + warfarin.",hint:"Apixaban/rivaroxaban lead directly.",tags:["VTE","DVT","PE","anticoagulation","DOAC"]},
{t:"VTE – treatment duration",top:"VTEs",mod:"CV & Haem",q:"How long should anticoagulation last for provoked vs unprovoked DVT?",a:"Provoked (risk factor in last 3 months): 3 months.\nUnprovoked: >3 months.\nActive cancer: 3–6 months.\nRecurrent: long-term.",hint:"If you can find a cause → 3 months; if not → longer.",tags:["VTE","duration","provoked","unprovoked"]},
{t:"Loop diuretics – MoA",top:"Oedema",mod:"CV & Haem",q:"What is the mechanism of action of loop diuretics and give 3 examples?",a:"Block Na+/K+/2Cl- cotransporter (NKCC2) at thick ascending limb of loop of Henle.\nExamples: furosemide, bumetanide, torasemide (London Fire Bridge).",hint:"Loop diuretics = most powerful natriuresis.",tags:["loop-diuretic","NKCC2","furosemide","mechanism"]},
{t:"Diuretics – side-effect comparison",top:"Oedema",mod:"CV & Haem",q:"Compare side-effects of loop/thiazide vs potassium-sparing diuretics.",a:"Loop/thiazide: hypokalaemia, hyperglycaemia, gout, hypotension.\nK-sparing (spironolactone): hyperkalaemia, gynaecomastia, libido change.\nAll: hyponatraemia + hypomagnesaemia.",hint:"Loop/thiazide = low K; K-sparing = high K.",tags:["diuretic","hypokalaemia","hyperkalaemia","spironolactone"]},
{t:"Stable angina – GTN counselling",top:"Stable Angina",mod:"CV & Haem",q:"How is an acute stable angina attack managed and what is the GTN bottle rule?",a:"GTN spray or sublingual tablet at onset or before precipitating event. Sit down (light-headedness).\nGTN sublingual tablets: discard 8 weeks after opening.\nTolerance: maintain nitrate-free period 10–14 hrs/day.",hint:"8-week GTN bottle clock.",tags:["angina","GTN","counselling","nitrate"]},
{t:"Stroke – acute ischaemic management",top:"Stroke",mod:"CV & Haem",q:"What is the acute treatment for ischaemic stroke?",a:"Alteplase (thrombolysis): within 4.5 hours (haemorrhagic excluded).\nAspirin 300 mg: until 2 weeks after onset.\nLong-term: clopidogrel 75 mg OD (use lansoprazole, not omeprazole).\nHigh-intensity statin ASAP. BP target systolic <130.",hint:"4.5 hour alteplase window. Clopidogrel + omeprazole = CYP2C19 interaction.",tags:["stroke","alteplase","thrombolysis","clopidogrel"]},
// ── CNS ───────────────────────────────────────────────────
{t:"GAD – pharmacological steps",top:"Anxiety",mod:"CNS",q:"What is the pharmacological treatment ladder for GAD?",a:"Crisis only: short-term benzodiazepine.\n1st chronic: SSRI (sertraline).\n2nd: alternative SSRI or SNRI.\n3rd: pregabalin.",hint:"SSRIs first chronically; benzos for crisis only.",tags:["anxiety","GAD","SSRI","pregabalin"]},
{t:"Benzodiazepine – MHRA + antidote",top:"Anxiety",mod:"CNS",q:"What is the key MHRA warning for benzodiazepines and the antidote?",a:"Fatal respiratory depression risk. Avoid with alcohol/CNS depressants. Hepatic impairment → coma.\nParadoxical effects: agitation, aggression, hallucinations.\nAntidote: flumazenil.",hint:"Flumazenil reverses benzos.",tags:["benzodiazepine","MHRA","flumazenil","respiratory"]},
{t:"Benzo driving limit – COLD FeeT",top:"Anxiety",mod:"CNS",q:"Name the 6 benzodiazepines with a legal driving limit.",a:"Clonazepam, Oxazepam, Lorazepam, Diazepam, Flunitrazepam, Temazepam.\nMnemonic: COLD FeeT.",hint:"COLD FeeT = legal limit benzos.",tags:["benzodiazepine","driving","COLD-FeeT","legal"]},
{t:"ADHD – treatment ladder",top:"ADHD",mod:"CNS",q:"What is the treatment ladder for ADHD in children ≥5 years?",a:"1st: methylphenidate.\n2nd: lisdexamfetamine (if MPH fails).\n3rd: dexamfetamine (if LDX intolerable duration).\nStimulant intolerance: atomoxetine or guanfacine.",hint:"MPH → LDX → Dex → Atomoxetine.",tags:["ADHD","methylphenidate","lisdexamfetamine","stimulant"]},
{t:"Methylphenidate – monitoring",top:"ADHD",mod:"CNS",q:"What parameters are monitored during methylphenidate treatment?",a:"Height, weight, heart rate, BP every 6 months.\nAssess for tics, sexual dysfunction, seizures, sleep, worsened behaviour.\nMR preparations: prescribe by brand only.",hint:"HWBP every 6 months.",tags:["methylphenidate","monitoring","ADHD","brand"]},
{t:"Bipolar – managing acute mania",top:"Bipolar Disorder",mod:"CNS",q:"How is acute mania managed in bipolar disorder?",a:"Stop any antidepressants. Offer antipsychotic (haloperidol, olanzapine, quetiapine, risperidone). If on lithium: check level, consider adding antipsychotic.",hint:"Antidepressants worsen mania – stop first.",tags:["bipolar","mania","antipsychotic","lithium"]},
{t:"Lithium – side-effects & toxicity",top:"Bipolar Disorder",mod:"CNS",q:"List lithium's main side-effects and signs of overdose.",a:"SEs: thyroid disorder, nephrotoxicity, lowered seizure threshold, QT prolongation, teratogenic (1st trimester).\nOverdose – SICK AND TREMOR: D+V, blurred vision, polyuria, drowsiness, confusion, fine resting tremor.",hint:"Fine resting tremor = classic early sign.",tags:["lithium","toxicity","tremor","SICK-AND-TREMOR"]},
{t:"Lithium – monitoring schedule",top:"Bipolar Disorder",mod:"CNS",q:"What are the lithium therapeutic ranges and monitoring schedule?",a:"First time: 0.6–0.8 mmol/L. Relapsed: 0.8–1 mmol/L.\nSample: 12 hours post-dose.\nWeekly until stable → 3-monthly yr 1 → 6-monthly.\nBefore + every 6 months: BMI, U&Es, eGFR, TFTs.\nPrescribe as brand.",hint:"12-hour sample; 6-monthly bloods; brand only.",tags:["lithium","monitoring","therapeutic-range","brand"]},
{t:"Lithium – interactions",top:"Bipolar Disorder",mod:"CNS",q:"What drug classes increase lithium toxicity risk?",a:"Diuretics, NSAIDs, metronidazole, ACEi/ARBs increase lithium levels.\nAlso: serotonin syndrome risk, QT-prolonging drugs, hypokalaemia-causing drugs (TdP risk).",hint:"DAMN drugs raise lithium: Diuretics, ACEi, Metronidazole, NSAIDs.",tags:["lithium","interactions","DAMN","NSAIDs","diuretics"]},
{t:"Dementia – treatment by type",top:"Dementia",mod:"CNS",q:"Match dementia types to pharmacological treatment.",a:"Alzheimer's mild–mod: AChEi (donepezil, galantamine, rivastigmine).\nModerate–severe: memantine.\nParkinson's dementia: rivastigmine (only licensed AChEi).\nFrontotemporal: NO AChEi or memantine.\nVascular: only if comorbid Alzheimer's/PD/Lewy body.",hint:"Frontotemporal = no AChEi. Rivastigmine only for PD dementia.",tags:["dementia","AChEi","donepezil","rivastigmine","memantine"]},
{t:"Dementia – AChEi side-effects",top:"Dementia",mod:"CNS",q:"Name specific side-effects linked to each AChEi.",a:"Donepezil: D+V, dizziness – take at bedtime.\nGalantamine: SJS, palpitations, seizures.\nRivastigmine: nausea/vomiting; fatal overdose risk with patch error – remove old patch before new one.",hint:"Rivastigmine patch = remove old before new. Galantamine = SJS risk.",tags:["AChEi","donepezil","galantamine","rivastigmine","patch"]},
{t:"Depression – SSRI treatment rules",top:"Depression",mod:"CNS",q:"When should antidepressants first be offered and what is the review timing?",a:"Not routinely for mild depression. Moderate–severe: SSRIs 1st line. Takes ~4 weeks for effect.\nReview within 2 weeks (1 week if 18–25 or suicide risk).\nContinue ≥6 months after remission.",hint:"4 weeks to work; 6 months after remission.",tags:["depression","SSRI","review","remission"]},
{t:"SSRIs – side-effects SQASH SIBS",top:"Depression",mod:"CNS",q:"List SSRI side-effects using the mnemonic.",a:"Suicidal ideation, QT prolongation, Appetite change, Seizures, Hepatic impairment, Sexual dysfunction, Insomnia (take in morning), Bleeding (GI), Serotonin syndrome.\nMnemonic: SQASH SIBS.",hint:"9 key SSRI SEs.",tags:["SSRI","side-effects","SQASH-SIBS","serotonin"]},
{t:"Serotonin syndrome – triad",top:"Depression",mod:"CNS",q:"What are the 3 components of serotonin syndrome and the most dangerous combination?",a:"1. Altered mental status (agitation, anxiety).\n2. Neuromuscular abnormalities (clonus, rigidity, hyperreflexia).\n3. Autonomic hyperactivity (tachycardia, hyperthermia, diaphoresis).\nMost dangerous: SSRI + MAOI.",hint:"Clonus = most specific sign. Never combine SSRI + MAOI.",tags:["serotonin-syndrome","SSRI","MAOI","clonus"]},
{t:"MAOIs – tyramine interaction",top:"Depression",mod:"CNS",q:"Why must MAOI patients avoid tyramine foods? Give 3 examples.",a:"MAOIs inhibit MAO-A → tyramine accumulates → hypertensive crisis.\nFoods: mature cheese, salami, marmite, yeast, tofu.\nPhenylephrine → hypertensive crisis.",hint:"Cheese, salami, marmite = classic MAOI exam trio.",tags:["MAOI","tyramine","hypertensive-crisis","food"]},
{t:"MAOI – washout periods",top:"Depression",mod:"CNS",q:"How long must you wait before starting an MAOI after stopping an SSRI?",a:"After SSRI: 1 week (5 weeks for fluoxetine).\nAfter TCA: 1–2 weeks (3 weeks for clomipramine/imipramine).\nAfter MAOI: 2 weeks.\nAfter MAOI before new antidepressant: 2 weeks.",hint:"Fluoxetine needs 5 weeks – the one that always catches people out.",tags:["MAOI","washout","fluoxetine","SSRI"]},
{t:"Epilepsy – focal seizure treatment",top:"Epilepsy",mod:"CNS",q:"What are first and second-line treatments for focal seizures?",a:"1st: lamotrigine or levetiracetam (2 L's).\n2nd: carbamazepine, oxcarbazepine, zonisamide (COZ).",hint:"2 L's focused; COZ we do second line.",tags:["epilepsy","focal","lamotrigine","levetiracetam"]},
{t:"Status epilepticus – management",top:"Epilepsy",mod:"CNS",q:"How is status epilepticus (>5 min) managed step-by-step?",a:"Hospital: IV lorazepam. Community: buccal midazolam or rectal diazepam.\nNo response ×2 benzos: levetiracetam, phenytoin, or valproate.\nStill no response: phenobarbital or general anaesthesia.",hint:"Benzos → LEV/PHT/VPA → phenobarbital/GA.",tags:["status-epilepticus","lorazepam","levetiracetam","phenytoin"]},
{t:"Valproate – pregnancy restrictions",top:"Epilepsy",mod:"CNS",q:"What are the current restrictions on sodium valproate prescribing?",a:"Not in under-55s unless 2 specialists confirm no alternative.\nPPP mandatory for women of childbearing potential.\nMen + female partners: contraception during + 3 months after.",hint:"Most teratogenic AED – PPP mandatory.",tags:["valproate","teratogen","PPP","epilepsy","pregnancy"]},
{t:"Epilepsy – driving rules",top:"Epilepsy",mod:"CNS",q:"What are the DVLA rules for driving after an epileptic seizure?",a:"Must inform DVLA and stop driving immediately.\nReapply after 1 seizure-free year (or 6 months if first seizure + low recurrence risk).\nChanging/reducing AEDs: no driving for 6 months.",hint:"1 year seizure-free to drive.",tags:["epilepsy","DVLA","driving","seizure-free"]},
{t:"Migraine – acute treatment",top:"Migraines",mod:"CNS",q:"What is the first-line acute migraine treatment?",a:"Triptan + aspirin/ibuprofen/paracetamol.\nAdd antiemetic: metoclopramide or prochlorperazine.\nTriptan at pain onset (not aura). Don't repeat if 1st dose fails.",hint:"Triptan + NSAID combination beats monotherapy.",tags:["migraine","triptan","NSAID","antiemetic"]},
{t:"Migraine – prophylaxis",top:"Migraines",mod:"CNS",q:"Name first-line migraine prophylaxis options.",a:"1st: propranolol, topiramate, amitriptyline.\n2nd: candesartan, sodium valproate.\nDo NOT offer gabapentin.",hint:"PTA prophylaxis: Propranolol, Topiramate, Amitriptyline.",tags:["migraine","prophylaxis","propranolol","topiramate"]},
{t:"Parkinson's – treatment decision",top:"Parkinson's Disease",mod:"CNS",q:"How does quality of life affect Parkinson's drug choice?",a:"Symptoms affect QoL: levodopa (+ carbidopa/benserazide).\nDon't affect QoL: dopamine agonist, levodopa, or MAO-B inhibitor.\nDyskinesia despite levodopa: add dopamine agonist, MAO-B inhibitor, or COMT inhibitor.",hint:"Levodopa for functional impairment; agonist/MAO-B for milder.",tags:["Parkinson","levodopa","dopamine-agonist","COMT"]},
{t:"Parkinson's – levodopa side-effects",top:"Parkinson's Disease",mod:"CNS",q:"What are the notable side-effects of levodopa?",a:"Impulse control disorders (gambling, hypersexuality, binge eating, compulsive spending).\nSudden sleep onset.\nRed urine.\nDo not withdraw abruptly.",hint:"Impulse-Sleep-Red urine triad.",tags:["levodopa","impulse-control","sleep","Parkinson"]},
{t:"Antipsychotic side-effect profiles",top:"Psychosis",mod:"CNS",q:"Which antipsychotics cause weight gain, hyperglycaemia, and postural hypotension?",a:"Weight gain: WOC – olanzapine, clozapine.\nHyperglycaemia: ROQ-C – risperidone, olanzapine, quetiapine, clozapine.\nPostural hypotension: ARCQed – aripiprazole, risperidone, clozapine, quetiapine.",hint:"ROQ-C = sweet lady. WOC = heavy. ARCQed = falls.",tags:["antipsychotic","weight","hyperglycaemia","postural-hypotension"]},
{t:"Antipsychotic monitoring",top:"Psychosis",mod:"CNS",q:"What monitoring parameters are required when starting an antipsychotic?",a:"Weight: start, weekly ×6, 12 wks, 1 yr, yearly.\nFasting glucose/HbA1c/lipids/BP: start, 12 wks, 1 yr, yearly.\nECG: before initiation.\nFBC/U&E/eGFR/LFTs: start then yearly.\nProlactin: 6 months then yearly.",hint:"Metabolic monitoring at 12 weeks is the key interval most miss.",tags:["antipsychotic","monitoring","metabolic","ECG"]},
{t:"Clozapine – FBC monitoring",top:"Psychosis",mod:"CNS",q:"What is the clozapine FBC monitoring schedule?",a:"Only after 2+ antipsychotics (including 1 second-generation) have failed.\nFBC: weekly ×18 wks → fortnightly until 1 yr → monthly.\nContinue 4 wks after stopping.",hint:"Agranulocytosis = mandatory lifelong FBC.",tags:["clozapine","FBC","agranulocytosis","monitoring"]},
{t:"Insomnia – z-hypnotics",top:"Sleeping Disorders",mod:"CNS",q:"What are the z-hypnotics and key counselling points?",a:"Zolpidem and zopiclone. Max 4 weeks. Take 2–3 nights/week (not every night). Takes ~1 hour to work.\nSEs: metallic/bitter taste, falls (especially age 65+).",hint:"Bitter taste + fall risk = zopiclone essentials.",tags:["insomnia","zopiclone","zolpidem","falls"]},
{t:"Alcohol withdrawal management",top:"Substance Dependence",mod:"CNS",q:"How are alcohol withdrawal symptoms, seizures, and Wernicke's managed?",a:"Symptoms: chlordiazepoxide or diazepam.\nSeizures: lorazepam.\nDelirium: lorazepam (2nd: haloperidol).\nWernicke's: thiamine (B1).",hint:"Chlordiazepoxide for symptoms; thiamine for Wernicke's.",tags:["alcohol","withdrawal","Wernicke","thiamine"]},
{t:"Opioid detox – methadone vs buprenorphine",top:"Substance Dependence",mod:"CNS",q:"Compare methadone and buprenorphine for opioid detoxification.",a:"Both 1st line; if equal → methadone preferred (better retention, heavy heroin use).\nBuprenorphine: lower fatal OD risk, can combine with naloxone, less clouding.\nMethadone: QT prolongation risk.",hint:"Buprenorphine = safer OD; methadone = better retention.",tags:["opioid","methadone","buprenorphine","detox"]},
// ── PHARMACOLOGY ─────────────────────────────────────────
{t:"Antidotes – complete list",top:"Drug Toxicity",mod:"Pharmacology",q:"Name the antidote for: apixaban, dabigatran, warfarin, heparin, digoxin, CCBs, beta-blockers, opioids, benzodiazepines, paracetamol, iron, methotrexate.",a:"Apixaban→andexanet alfa. Dabigatran→idarucizumab. Warfarin→phytomenadione. Heparin→protamine. Digoxin→digoxin-specific antibody. CCBs→calcium chloride. Beta-blockers→glucagon. Opioids→naloxone. Benzos→flumazenil. Paracetamol→acetylcysteine. Iron→deferoxamine. Methotrexate→folinic acid.",hint:"CCB→calcium; BB→glucagon; Paracetamol→acetylcysteine – three unexpected antidotes.",tags:["antidote","toxicity","reversal"]},
{t:"Drug toxicity mnemonics",top:"Drug Toxicity",mod:"Pharmacology",q:"Give toxicity mnemonics for lithium, digoxin, and theophylline.",a:"Lithium – SICK AND TREMOR: D+V, blurred vision, polyuria, drowsiness, confusion, tremor.\nDigoxin – SICK AND SLOW: D+V, yellow vision, confusion, bradycardia.\nTheophylline – SICK AND FAST: vomiting, tremor, palpitations, arrhythmias.",hint:"Tremor=lithium; Slow=digoxin; Fast=theophylline.",tags:["toxicity","mnemonic","lithium","digoxin","theophylline"]},
{t:"CYP450 – key inducers",top:"CYP450 Enzymes",mod:"Pharmacology",q:"Name the major CYP450 enzyme inducers and their effect.",a:"Rifampicin, carbamazepine, phenytoin, phenobarbital, St John's Wort, chronic alcohol, efavirenz.\nInducers REDUCE drug levels → treatment failure.",hint:"Rifampicin = most potent inducer.",tags:["CYP450","inducers","rifampicin","carbamazepine"]},
{t:"CYP450 – key inhibitors",top:"CYP450 Enzymes",mod:"Pharmacology",q:"Name the major CYP450 enzyme inhibitors and their effect.",a:"Amiodarone, fluoxetine, fluconazole, erythromycin, clarithromycin, grapefruit juice, ciprofloxacin, valproate, omeprazole.\nInhibitors INCREASE drug levels → toxicity.",hint:"Grapefruit + clarithromycin = classic exam inhibitors.",tags:["CYP450","inhibitors","grapefruit","clarithromycin"]},
{t:"QT prolongation – ABCDE drugs",top:"QT Prolongation",mod:"Pharmacology",q:"Name the drug classes that prolong QT using the ABCDE mnemonic.",a:"A – Antiarrhythmics (amiodarone, sotalol)\nB – aBiotics (macrolides, quinolones)\nC – antipsyChotics (haloperidol)\nD – antiDepressants (citalopram, TCAs)\nE – antifungals/antiEmetics (fluconazole, domperidone)",hint:"ABCDE of QT prolongation.",tags:["QT","ABCDE","amiodarone","macrolide","antipsychotic"]},
{t:"Anti-muscarinic side-effects",top:"Anti-Muscarinic Medications",mod:"Pharmacology",q:"List the 8 classic anti-muscarinic side-effects.",a:"Dry mouth, blurred vision, urinary retention, constipation, tachycardia, confusion/delirium (elderly), reduced sweating, mydriasis.\nMnemonic: Can't See, Can't Pee, Can't Spit, Can't Sh**.",hint:"Elderly at highest risk of confusion and falls.",tags:["antimuscarinic","side-effects","elderly","urinary-retention"]},
{t:"Hypokalaemia – drug causes",top:"Electrolytes",mod:"Pharmacology",q:"Name 5 drug classes that cause hypokalaemia and why.",a:"Loop diuretics (NKCC2 block). Thiazides (distal tubule). Corticosteroids (mineralocorticoid effect). Beta-2 agonists (K+ cellular shift). Insulin (K+ shift into cells).",hint:"Loop + thiazide most common. Beta-2 agonists in asthma also lower K+.",tags:["hypokalaemia","electrolyte","diuretic","insulin","beta-2"]},
{t:"Hyperkalaemia – drug causes",top:"Electrolytes",mod:"Pharmacology",q:"Name 5 drug classes that cause hyperkalaemia.",a:"ACEi, ARBs (less aldosterone → K+ retention). K-sparing diuretics. NSAIDs (reduce renal K+ excretion). Heparin (reduces aldosterone synthesis). Trimethoprim (blocks renal K+ secretion).",hint:"ACEi + K-sparing + NSAIDs = dangerous triple.",tags:["hyperkalaemia","ACEi","NSAIDs","spironolactone","trimethoprim"]},
{t:"Hypokalaemia – management",top:"Electrolytes",mod:"Pharmacology",q:"How is hypokalaemia managed across severity levels?",a:"Mild (3.0–3.4): dietary sources + oral replacement (Sando-K).\nModerate (2.5–2.9): oral replacement.\nSevere (<2.5): IV KCl in hospital.\nCaution with oral K in renal impairment (rebound hyperkalaemia).",hint:"<2.5 = hospital IV.",tags:["hypokalaemia","KCl","electrolyte","severity"]},
{t:"Hyperkalaemia – acute severe treatment",top:"Electrolytes",mod:"Pharmacology",q:"What is the treatment sequence for acute severe hyperkalaemia (≥6.5 mmol/L)?",a:"IV calcium chloride 10% over 5 min (stabilise myocardium).\nThen IV insulin-glucose (10 units soluble insulin + 25g glucose) + 10% glucose infusion.\nAlso: nebulised salbutamol 10–20 mg.\nReview causative medications.",hint:"Calcium-Insulin-Salbutamol. Stabilise, shift, review.",tags:["hyperkalaemia","calcium","insulin","salbutamol","acute"]},
{t:"Renal clearance – dose adjustments",top:"Clearance Organs",mod:"Pharmacology",q:"Name 5 drugs requiring dose reduction or avoidance in renal impairment.",a:"Metformin: avoid if eGFR <30 (lactic acidosis).\nDOACs: dose-reduce per thresholds.\nLithium: renally cleared – dose-reduce.\nMethotrexate: avoid severe impairment.\nNSAIDs: avoid (reduce renal blood flow).",hint:"Mr LIMN – Metformin, LMW heparin, renal drugs, NSAIDs.",tags:["renal","eGFR","metformin","dose-adjustment","DOAC"]},
{t:"Blood dyscrasias – causative drugs",top:"Blood Disorders",mod:"Pharmacology",q:"Name 4 drugs associated with agranulocytosis/neutropenia.",a:"Clozapine: mandatory FBC schedule.\nCarbamazepine: FBC before + during.\nMethotrexate: FBC + LFTs + renal.\nCarbimazole: stop + urgent FBC if sore throat/fever.",hint:"Carbimazole sore throat = FBC immediately.",tags:["agranulocytosis","clozapine","carbamazepine","carbimazole","methotrexate"]},
// ── ENDOCRINOLOGY ─────────────────────────────────────────
{t:"Addison's disease – treatment",top:"Addison's Disease",mod:"Endocrinology",q:"What hormone replacements are used in Addison's disease and what is given in adrenal crisis?",a:"Glucocorticoid: hydrocortisone or prednisolone.\nMineralocorticoid: fludrocortisone.\nAndrogen (unlicensed): DHEA.\nAdrenal crisis: IM/IV hydrocortisone + IV saline infusion.",hint:"Replace BOTH glucocorticoid AND mineralocorticoid. Crisis = IV hydrocortisone.",tags:["Addison","hydrocortisone","fludrocortisone","adrenal-crisis"]},
{t:"Corticosteroids – potency classification",top:"Corticosteroids",mod:"Endocrinology",q:"Which steroids have highest glucocorticoid vs mineralocorticoid activity?",a:"Highest glucocorticoid: dexamethasone, betamethasone.\nHighest mineralocorticoid: fludrocortisone, hydrocortisone.\nDexamethasone/betamethasone: negligible fluid retention.",hint:"Dexa/Beta = anti-inflammatory, no fluid retention. Fludro = fluid retention.",tags:["corticosteroid","potency","dexamethasone","fludrocortisone"]},
{t:"Corticosteroid side-effects",top:"Corticosteroids",mod:"Endocrinology",q:"Name 6 glucocorticoid and 3 mineralocorticoid side-effects.",a:"Glucocorticoid: diabetes, osteoporosis, avascular necrosis, gastric ulceration, Cushing's syndrome, immunosuppression.\nMineralocorticoid: Na/water retention → hypertension, K+ loss → hypokalaemia, Ca2+ loss → hypocalcaemia.",hint:"Glucocorticoid = long-term damage (bones, sugar, stomach).",tags:["corticosteroid","side-effects","Cushing","osteoporosis"]},
{t:"Corticosteroid withdrawal – when to taper",top:"Corticosteroids",mod:"Endocrinology",q:"When must corticosteroids be tapered rather than stopped abruptly?",a:"Must taper if: >3 weeks use; >40 mg prednisolone/day >1 week; repeat evening doses; recent repeated courses; previous long-term therapy.\nShort courses <3 weeks = stop abruptly.",hint:"<3 weeks = stop abruptly. Longer = taper to prevent adrenal crisis.",tags:["corticosteroid","withdrawal","taper","adrenal-insufficiency"]},
{t:"Topical steroid potencies",top:"Corticosteroids",mod:"Endocrinology",q:"Classify topical steroid potencies from mild to very potent with examples.",a:"Mild: hydrocortisone.\nModerate: clobetasone.\nPotent: betamethasone.\nVery potent: clobetasol.",hint:"Hydro-Clobetasone-Beta-Clobetasol – increasing potency.",tags:["topical-steroid","potency","clobetasol","hydrocortisone"]},
{t:"Diabetes insipidus – types and treatment",top:"Diabetes Insipidus",mod:"Endocrinology",q:"Compare cranial vs nephrogenic diabetes insipidus and their treatments.",a:"Cranial: ADH deficiency → desmopressin or vasopressin.\nNephrogenic: ADH resistance → thiazide diuretic (paradoxical).\nDesmopressin CI: >65 yrs, history of hyponatraemia, diuretic use.",hint:"Cranial = no ADH → give it. Nephrogenic = thiazide paradox.",tags:["diabetes-insipidus","desmopressin","thiazide","ADH"]},
{t:"SIADH – treatment",top:"Excessive ADH Secretion",mod:"Endocrinology",q:"How is SIADH treated?",a:"Fluid restriction (1st line), demeclocycline, tolvaptan.\nTolvaptan warning: rapid correction → osmotic demyelination → serious neurological events.",hint:"Tolvaptan = correct sodium too fast → osmotic demyelination.",tags:["SIADH","tolvaptan","hyponatraemia","demeclocycline"]},
{t:"Diabetes – medication-induced",top:"Diabetes Mellitus",mod:"Endocrinology",q:"Which drug classes can induce diabetes/hyperglycaemia?",a:"Antipsychotics (ROQ-C: risperidone, olanzapine, quetiapine, clozapine), beta-blockers, glucocorticoids, statins.",hint:"ROQ-C antipsychotics = glucose. Steroids = steroid-induced diabetes.",tags:["diabetes","drug-induced","antipsychotic","steroid"]},
{t:"Diabetes driving – key rules",top:"Diabetes Mellitus",mod:"Endocrinology",q:"What are the DVLA rules for insulin-treated diabetic drivers?",a:"Must notify DVLA. Check glucose <2 hrs before driving + every 2 hrs.\nBG <5 → snack; <4 → DO NOT DRIVE.\nHypo whilst driving: stop, engine off, keys out, move from seat, treat, wait 45 min after BG >5.",hint:"<4 mmol/L = stop driving. 45-minute rule after recovery.",tags:["diabetes","DVLA","driving","hypoglycaemia"]},
{t:"DKA – diagnostic criteria and treatment",top:"Diabetes Complications",mod:"Endocrinology",q:"What 3 criteria confirm DKA and what is the treatment?",a:"All 3: BG >11 mmol/L + ketones >3 mmol/L + venous pH <7.3.\nTreatment: IV 0.9% NaCl ± KCl, IV human soluble insulin.\nResolution: ketones <0.6 mmol/L + pH >7.3.",hint:"DKA = glucose + ketones + acidosis. All three required.",tags:["DKA","ketones","insulin","IV-fluids"]},
{t:"Hypoglycaemia – treatment by severity",top:"Diabetes Complications",mod:"Endocrinology",q:"How is hypoglycaemia treated by severity?",a:"Mild/moderate (conscious): 10–20 g fast-acting carbs. Recheck every 15 min.\nSevere (unconscious): IM glucagon or IV glucose.\nAlcohol-induced: IV glucose only (glucagon ineffective).",hint:"Alcohol + hypo = IV glucose ONLY.",tags:["hypoglycaemia","glucagon","glucose","alcohol"]},
{t:"T2DM – no comorbidities pathway",top:"Type 2 Diabetes",mod:"Endocrinology",q:"Outline the T2DM treatment pathway with no relevant comorbidities.",a:"1st: metformin + SGLT-2i.\n2nd (target not met): + DPP-4i.\n3rd: SU, pioglitazone, or insulin.\nHbA1c targets: 48 (no hypo risk); 53 (SU/insulin).",hint:"Metformin + SGLT-2i first, DPP-4i second.",tags:["T2DM","metformin","SGLT2","DPP4","HbA1c"]},
{t:"T2DM – CVD pathway",top:"Type 2 Diabetes",mod:"Endocrinology",q:"What is the T2DM treatment pathway for established atherosclerotic CVD?",a:"1st: metformin + SGLT-2i + SC semaglutide.\n2nd (target not reached): + SU, pioglitazone, or insulin.\nIf CVD develops after treatment initiation: add SC semaglutide.",hint:"CVD = semaglutide specifically indicated.",tags:["T2DM","CVD","semaglutide","GLP1"]},
{t:"T2DM – CKD pathway",top:"Type 2 Diabetes",mod:"Endocrinology",q:"How does CKD affect T2DM drug choices?",a:"eGFR 20–30: dapagliflozin or empagliflozin alone.\neGFR <20: DPP-4i.\nAvoid SU if eGFR <30. Stop metformin if eGFR <30.",hint:"eGFR <30: no metformin, no SU. eGFR <20: DPP-4i only.",tags:["T2DM","CKD","eGFR","metformin","SGLT2"]},
{t:"Metformin – side-effects and cautions",top:"Type 2 Diabetes",mod:"Endocrinology",q:"What are metformin's main side-effects and when must it be stopped?",a:"GI SEs (nausea, D+V – increase dose slowly or use MR).\nLactic acidosis: avoid if eGFR <30.\nMHRA: reduces vitamin B12.\nSTOP if: AKI, eGFR drops <30, dehydration (sick day rules).",hint:"B12 low + lactic acidosis + AKI = stop metformin.",tags:["metformin","lactic-acidosis","B12","AKI","sick-day"]},
{t:"SGLT-2i – MHRA warnings",top:"Type 2 Diabetes",mod:"Endocrinology",q:"List the 4 MHRA warnings for SGLT-2 inhibitors.",a:"1. DKA (can be euglycaemic) – monitor ketones during illness/surgery.\n2. Fournier's gangrene.\n3. Lower-limb amputation: canagliflozin only.\n4. Volume depletion.",hint:"Fournier's = most alarming. Canagliflozin = amputation.",tags:["SGLT2","MHRA","DKA","Fournier","canagliflozin"]},
{t:"GLP-1 agonists – MHRA warnings",top:"Type 2 Diabetes",mod:"Endocrinology",q:"What are the key MHRA warnings for GLP-1 receptor agonists?",a:"1. DKA when insulin rapidly reduced.\n2. Pulmonary aspiration risk during GA (delayed gastric emptying).\n3. Semaglutide: non-arteritic anterior ischaemic optic neuropathy (sudden vision loss → urgent referral).\n4. Misuse potential.",hint:"Semaglutide optic neuropathy = sudden unilateral vision loss → urgent referral.",tags:["GLP1","semaglutide","MHRA","optic-neuropathy","aspiration"]},
{t:"Insulin types – onset and duration",top:"Type 1 Diabetes",mod:"Endocrinology",q:"Compare rapid-acting, soluble, intermediate, and long-acting insulins.",a:"Rapid-acting (lispro/aspart/glulisine – NO LAG): onset <15 min, 2–5 hrs – with/just before meal.\nSoluble: onset 30–60 min, ≤8 hrs.\nIntermediate: onset 1–2 hrs, 11–24 hrs.\nLong-acting (detemir/degludec/glargine): 24 hrs (degludec = 42 hrs).",hint:"LAG = no lag (rapid-acting). Degludec = longest at 42 hrs.",tags:["insulin","rapid-acting","long-acting","degludec"]},
{t:"Insulin storage and injection sites",top:"Type 1 Diabetes",mod:"Endocrinology",q:"How should insulin be stored and what are the injection site absorption rates?",a:"Unopened: fridge 2–8°C, don't freeze. In use: room temp for 28 days. Remove from fridge 15–20 min before injection.\nAbsorption (fastest to slowest): abdomen > thighs > buttocks.\nRotate sites to prevent lipohypertrophy.",hint:"Abdomen = fastest. Rotate to prevent lipohypertrophy.",tags:["insulin","storage","injection","lipohypertrophy"]},
{t:"Gestational diabetes – treatment",top:"Gestational Diabetes",mod:"Endocrinology",q:"How is gestational diabetes managed based on fasting BG?",a:"Fasting BG <7: diet/exercise → if targets not met in 1–2 wks → metformin → add insulin if needed.\nFasting BG >7: diet/exercise + insulin ± metformin.\nSTOP treatment after birth.",hint:"BG <7 = try metformin first. BG >7 = insulin straight away.",tags:["gestational-diabetes","metformin","insulin","pregnancy"]},
{t:"HRT – regimens and uterus status",top:"Menopause",mod:"Endocrinology",q:"When is combined HRT used vs oestrogen-only?",a:"Uterus present: oestrogen + progestogen (endometrial protection).\nNo uterus: oestrogen alone.\nPerimenopause: monthly or 3-monthly cyclical (NOT continuous).",hint:"Uterus = add progestogen. Perimenopause = cyclical only.",tags:["HRT","menopause","oestrogen","progestogen"]},
{t:"HRT – risks by route",top:"Menopause",mod:"Endocrinology",q:"How does HRT route affect VTE, stroke, breast and endometrial cancer risk?",a:"VTE + stroke: oral > transdermal.\nBreast cancer: combined > oestrogen-only; risk persists 10+ years.\nEndometrial cancer: combined = LOWER risk than oestrogen-only.",hint:"Transdermal safer for VTE/stroke. Combined = more breast but less endometrial.",tags:["HRT","VTE","breast-cancer","transdermal"]},
{t:"HRT – when to stop + surgery",top:"Menopause",mod:"Endocrinology",q:"When should HRT be stopped and what is the rule for elective surgery?",a:"Stop immediately for: jaundice, significant BP rise, new migraine, pregnancy, VTE, severe CNS effects, prolonged immobility.\nElective surgery: stop 4–6 weeks before; restart when fully mobile.",hint:"Stop HRT 4–6 weeks before elective surgery – VTE risk.",tags:["HRT","surgery","VTE","stop"]},
{t:"Osteoporosis – bisphosphonate MHRA warnings",top:"Osteoporosis",mod:"Endocrinology",q:"What are the 3 MHRA warnings for bisphosphonates?",a:"Atypical femoral fractures (thigh/hip/groin pain).\nOsteonecrosis of jaw (dental pain/swelling).\nOsteonecrosis of external auditory canal (ear pain/discharge).\nReview need after 5 years (3 years for zoledronic acid).",hint:"Jaw, Femur, Ear – three bisphosphonate warnings.",tags:["bisphosphonate","MHRA","osteonecrosis","femur","jaw"]},
{t:"Bisphosphonates – counselling",top:"Osteoporosis",mod:"Endocrinology",q:"Give 4 key counselling points for oral bisphosphonates.",a:"Take with full glass of water. Remain upright ≥30 min. Take 30 min before food/other meds. Never double-dose. Avoid NSAIDs (GI irritation).",hint:"Upright 30 min after. Never double-dose.",tags:["bisphosphonate","counselling","osteoporosis","upright"]},
{t:"Hyperthyroidism – treatment",top:"Thyroid Disorders",mod:"Endocrinology",q:"What is first-line treatment for hyperthyroidism and Grave's disease?",a:"Hyperthyroidism: carbimazole (1st line). Beta-blockers for symptom relief.\nGrave's: radioactive iodine (1st). Carbimazole if iodine/surgery unsuitable. Block-and-replace + levothyroxine 12–18 months.\nPregnancy: propylthiouracil.",hint:"Grave's = radioiodine 1st. Pregnancy = propylthiouracil.",tags:["hyperthyroid","carbimazole","radioiodine","Graves","propylthiouracil"]},
{t:"Carbimazole – MHRA warnings",top:"Thyroid Disorders",mod:"Endocrinology",q:"What are the 3 MHRA warnings for carbimazole?",a:"1. Congenital malformations – strengthened contraception advice.\n2. Acute pancreatitis – stop immediately and permanently.\n3. Bone marrow suppression – report and stop if sore throat/fever.",hint:"Sore throat on carbimazole = stop + FBC immediately.",tags:["carbimazole","MHRA","agranulocytosis","pancreatitis"]},
{t:"Levothyroxine – monitoring and interactions",top:"Thyroid Disorders",mod:"Endocrinology",q:"How is levothyroxine monitored and what are its key interactions?",a:"Monitor TSH: every 3 months until stable, then yearly.\nTake in morning ≥30 min before food/caffeine. Prescribe by brand (MHRA).\nInteractions: antacids/calcium/ferrous sulphate reduce absorption (≥2–4 hr gap). Orlistat reduces absorption.",hint:"30 min before food, brand only, 4-hr gap from antacids/iron.",tags:["levothyroxine","TSH","brand","absorption","antacid"]},
// ── GI ────────────────────────────────────────────────────
{t:"Laxative classes – MoA & onset",top:"Constipation",mod:"GI",q:"Compare MoA and onset for bulk-forming, osmotic, stimulant, and softening laxatives.",a:"Bulk-forming (ispaghula): retains fluid → peristalsis. 2–3 days.\nOsmotic (macrogol/lactulose): pulls fluid into bowel. 2–3 days.\nStimulant (senna/bisacodyl): stimulates colonic nerves. 6–12 hrs.\nSofteners (docusate): allows water into stool. 15–30 min.",hint:"Bulk=2d; Osmotic=2d; Stimulant=6-12h; Softener=30min.",tags:["laxative","constipation","bulk","stimulant","osmotic"]},
{t:"Opioid-induced constipation",top:"Constipation",mod:"GI",q:"How is opioid-induced constipation managed?",a:"AVOID bulk-forming (obstruction risk).\nUse osmotic + stimulant.\nIf no response: naldemedine or naloxegol.",hint:"No bulk in opioid constipation.",tags:["opioid","constipation","naloxegol","laxative"]},
{t:"GORD – treatment pathway",top:"Gastric Acid",mod:"GI",q:"Outline GORD treatment including lifestyle, drugs, and urgent referral.",a:"Lifestyle first. PPI 4–8 weeks (8 if severe oesophagitis) or H2 antagonist. Pregnancy: antacids/alginates.\nUrgent refer: GI bleed, dysphagia, unexplained weight loss, ≥55 yrs, appetite loss.",hint:"PPI 4–8 wks. Red flags = urgent refer.",tags:["GORD","PPI","H2-antagonist","red-flags"]},
{t:"H. pylori – eradication therapy",top:"Gastric Acid",mod:"GI",q:"What is H. pylori triple therapy and what testing rules apply?",a:"PPI + 2 of: amoxicillin 1000 mg BD, clarithromycin 500 mg BD, metronidazole 400 mg BD.\nStop PPI ≥2 weeks before testing; antibiotics ≥4 weeks before.",hint:"Stop PPI 2 weeks, antibiotics 4 weeks before testing.",tags:["H.pylori","eradication","triple-therapy","PPI"]},
{t:"Antacids – interactions",top:"Gastric Acid",mod:"GI",q:"Name 4 drugs with impaired absorption when taken with antacids.",a:"Bisphosphonates: take 30 min before antacid.\nTetracyclines: ≥2–3 hours.\nQuinolones: 2 hrs before or 4 hrs after.\nDigoxin: ≥2 hours.\nMechanism: ↑pH + chelation.",hint:"BisQTD – Bisphosphonates, Quinolones, Tetracyclines, Digoxin.",tags:["antacid","interaction","absorption","chelation"]},
{t:"Crohn's vs UC – key differences",top:"IBD",mod:"GI",q:"Compare Crohn's and UC on location, depth, pattern, and risk factors.",a:"Crohn's: anywhere GI, full-thickness, patchy, smoking worsens.\nUC: large bowel only, superficial, continuous, smoking is PROTECTIVE.",hint:"Crohn's = patchy + deep. UC = continuous + superficial.",tags:["IBD","Crohns","UC","smoking"]},
{t:"Crohn's – acute treatment",top:"IBD",mod:"GI",q:"Outline the acute treatment of Crohn's disease.",a:"First flare: prednisolone/IV hydrocortisone. Budesonide if steroids CI or distal ileal/ileocaecal.\n≥2 flares/year: add azathioprine/mercaptopurine (check TPMT first).\nSevere: infliximab or adalimumab.",hint:"TPMT deficiency = can't use azathioprine. Check FIRST.",tags:["Crohns","prednisolone","azathioprine","TPMT","infliximab"]},
{t:"UC – acute severe treatment",top:"IBD",mod:"GI",q:"How is severe acute UC managed step-by-step?",a:"Step 1: IV hydrocortisone or methylprednisolone. Consider IV ciclosporin or surgery if steroids CI.\nStep 2 (no improvement in 72 hrs): add IV ciclosporin. Use infliximab if ciclosporin CI.",hint:"72-hour rule – IV steroids fail → ciclosporin or surgery.",tags:["UC","hydrocortisone","ciclosporin","infliximab","72-hours"]},
{t:"IBS – pharmacological treatment",top:"IBS",mod:"GI",q:"How are IBS symptoms managed pharmacologically?",a:"Constipation: bulk-forming laxative (NOT lactulose in IBS).\nDiarrhoea: loperamide.\nAbdominal pain/spasm: mebeverine, alverine, peppermint oil.\nRefractory pain: low-dose TCA or SSRI.",hint:"No lactulose in IBS – causes bloating.",tags:["IBS","loperamide","mebeverine","lactulose"]},
{t:"Loperamide – MHRA warning",top:"Diarrhoea",mod:"GI",q:"What is the MHRA warning for loperamide and how is overdose treated?",a:"Serious cardiac reactions (QT prolongation) at high doses.\nMax OTC: 12 mg/day. Max licensed: 16 mg/day.\nOverdose antidote: naloxone.",hint:"Loperamide OD → naloxone. QT at high doses.",tags:["loperamide","QT","MHRA","naloxone","diarrhoea"]},
{t:"Haemorrhoids – management",top:"Haemorrhoids & Fissures",mod:"GI",q:"How are haemorrhoids managed and what analgesics should be avoided?",a:"Soft stools (fibre, fluids, laxative).\nPain: paracetamol (avoid codeine = constipation; avoid NSAIDs = bleeding).\nTopical anaesthetics ≤few days; corticosteroids ≤7 days.",hint:"Codeine worsens haemorrhoids. NSAIDs cause bleeding.",tags:["haemorrhoids","codeine","NSAIDs","topical"]},
{t:"Anal fissure – chronic management",top:"Haemorrhoids & Fissures",mod:"GI",q:"What is the treatment for chronic anal fissure (>6 weeks)?",a:"Topical GTN 0.4% ointment ×6–8 weeks (25% get headaches).\nAlternative: topical diltiazem 2% (fewer headaches).\nRefer for surgery if no improvement.",hint:"GTN = headaches (vasodilation). Diltiazem = less headache.",tags:["anal-fissure","GTN","diltiazem","headache"]},
{t:"Cholestasis – treatment",top:"Cholestasis",mod:"GI",q:"How is cholestatic pruritus treated and what is used in pregnancy?",a:"Cholestatic pruritus: cholestyramine, ursodeoxycholic acid, rifampicin.\nIntrahepatic cholestasis of pregnancy: ursodeoxycholic acid.",hint:"Ursodeoxycholic acid = go-to for both.",tags:["cholestasis","ursodeoxycholic","pruritus","pregnancy"]},
// ── UROLOGY & CONTRACEPTION ──────────────────────────────
{t:"Contraception – POP missed pill rules",top:"Contraception",mod:"Urology & Contraception",q:"Compare the missed pill windows for desogestrel, drospirenone, and other POPs.",a:"Desogestrel: >12 hrs late = missed.\nDrospirenone: >24 hrs late = missed.\nOther POPs: >3 hrs late = missed.\nIf missed: take ASAP, continue pack, extra precaution 48 hrs (7 days for drospirenone).",hint:"12-24-3 rule.",tags:["POP","contraception","missed-pill","desogestrel"]},
{t:"Copper IUD – MHRA warning",top:"Contraception",mod:"Urology & Contraception",q:"What is the MHRA warning for copper IUDs and when should a patient be referred?",a:"MHRA: risk of uterine perforation.\nRefer if: coil expelled, new-onset pelvic pain, unable to feel threads.\nRemove in first 12 weeks of pregnancy. Replace every 5–10 years.",hint:"Can't feel threads = possible expulsion or perforation → refer.",tags:["IUD","MHRA","perforation","contraception"]},
{t:"Urinary incontinence – treatment",top:"Urinary Incontinence",mod:"Urology & Contraception",q:"Outline pharmacological treatment for stress and urgency urinary incontinence.",a:"Stress: pelvic floor exercises ≥3 months → duloxetine or surgery.\nUrgency: bladder training ≥6 weeks → antimuscarinic (oxybutynin, tolterodine) or beta-3 agonist (mirabegron). Add desmopressin if nocturia.\nAntimuscarinics CI: angle-closure glaucoma, GI motility disorders.",hint:"Stress = duloxetine. Urgency = antimuscarinic or mirabegron.",tags:["incontinence","duloxetine","mirabegron","antimuscarinic"]},
{t:"BPH – drug treatment",top:"Urinary Retention",mod:"Urology & Contraception",q:"What drugs are used in BPH and their mechanisms?",a:"Alpha-blockers (tamsulosin, doxazosin): relax smooth muscle → improve flow. First dose hypotension – give at bedtime.\n5-alpha-reductase inhibitors (finasteride, dutasteride): shrink prostate (takes months).",hint:"Alpha-blockers = immediate symptom relief. 5-ARI = shrinks prostate.",tags:["BPH","tamsulosin","finasteride","alpha-blocker"]},
{t:"Finasteride – MHRA warnings",top:"Urinary Retention",mod:"Urology & Contraception",q:"What are the MHRA warnings for finasteride?",a:"Depression and suicidal thoughts (stop immediately).\nSexual dysfunction and decreased libido (can persist after stopping).\nMale breast cancer: report lumps, pain, nipple discharge.\nPregnant women must NOT handle crushed tablets.",hint:"Finasteride = depression + sexual dysfunction that persists.",tags:["finasteride","MHRA","depression","teratogen","BPH"]},
{t:"Erectile dysfunction – PDE-5 inhibitors",top:"Erectile Dysfunction",mod:"Urology & Contraception",q:"Compare sildenafil and tadalafil. What are key PDE-5i contraindications?",a:"Sildenafil: 50 mg ~1 hr before sex (delayed by food), max 100 mg.\nTadalafil: 10 mg ~30 min before, max 20 mg; also 5 mg OD.\nCI: nitrates, recent MI/stroke, unstable angina, HF, hypotension (systolic <90), arrhythmias.\nPriapism (>4 hrs): seek medical attention.",hint:"PDE-5i + nitrates = catastrophic hypotension. Never co-prescribe.",tags:["sildenafil","tadalafil","PDE5","nitrate","erectile-dysfunction"]},
{t:"Nocturnal enuresis – treatment ladder",top:"Nocturnal Enuresis",mod:"Urology & Contraception",q:"Outline the treatment ladder for nocturnal enuresis.",a:"1st: lifestyle advice (<5 years often resolves alone).\n2nd: enuresis alarm (4 sessions, assess at 4 wks, continue until 2 wks dry).\n3rd: desmopressin (>5 years).\n4th: desmopressin + antimuscarinic.\nLast: imipramine.",hint:"Alarm → desmopressin → add antimuscarinic → imipramine last.",tags:["enuresis","desmopressin","alarm","imipramine"]},
// ── ONCOLOGY ─────────────────────────────────────────────
{t:"Cytotoxic drug classes",top:"Cytotoxic Drugs",mod:"Oncology",q:"Name 8 classes of cytotoxic drugs with one example each.",a:"Alkylating: cyclophosphamide. Platinum: cisplatin. Antimetabolites: methotrexate. Anthracyclines: doxorubicin. Cytotoxic antibiotics: bleomycin. Taxanes: paclitaxel. Vinca alkaloids: vincristine. Aromatase inhibitors: anastrozole.",hint:"A-P-A-A-C-T-V-A – eight classes.",tags:["cytotoxic","chemotherapy","oncology","alkylating"]},
{t:"Tumour lysis syndrome",top:"Cytotoxin Side-Effects",mod:"Oncology",q:"What electrolyte changes occur in TLS and how is hyperuricaemia prevented?",a:"HYPER: K+, phosphate, uric acid.\nHYPO: calcium → renal damage + arrhythmias.\nPrevention: allopurinol 24 hrs before (or febuxostat 2 days before) + hydration.",hint:"HYPER K+Ph+Uric; HYPO Ca. Allopurinol 24 hrs before.",tags:["TLS","tumour-lysis","allopurinol","uric-acid","calcium"]},
{t:"Bone marrow suppression – cytotoxics",top:"Cytotoxin Side-Effects",mod:"Oncology",q:"When does cytotoxic BMS occur and which drugs are spared?",a:"Occurs 7–10 days after administration (nadir).\nAll drugs except vincristine and bleomycin cause BMS.\nCheck FBC before each cycle. Neutropenic fever: broad-spectrum antibiotics.",hint:"Nadir at day 7–10. Vincristine + bleomycin = no BMS.",tags:["BMS","nadir","vincristine","bleomycin","neutropenia"]},
{t:"Urothelial toxicity – cytotoxics",top:"Cytotoxin Side-Effects",mod:"Oncology",q:"Which cytotoxics cause urothelial toxicity and how is it treated?",a:"Cyclophosphamide and ifosfamide → haemorrhagic cystitis.\nTreatment: mesna (uroprotectant, given with drug).",hint:"Cyclo/Ifosfamide → haemorrhagic cystitis → Mesna prevents it.",tags:["cyclophosphamide","ifosfamide","mesna","haemorrhagic-cystitis"]},
{t:"Cytotoxic nausea – antiemetic protocol",top:"Cytotoxin Side-Effects",mod:"Oncology",q:"What antiemetics are used for low vs high emetogenic chemotherapy?",a:"Low (fluorouracil, vinca alkaloids): dexamethasone or lorazepam.\nModerate: dexamethasone + ondansetron.\nHigh (cisplatin, high-dose cyclophosphamide): ondansetron + dexamethasone + aprepitant.",hint:"High emetogenic = triple therapy (Ondansetron + Dexa + Aprepitant).",tags:["chemotherapy","antiemetic","ondansetron","aprepitant","emetogenic"]},
{t:"Azathioprine – TPMT and monitoring",top:"Immunosuppression",mod:"Oncology",q:"Why must TPMT be checked before azathioprine and what is the allopurinol interaction?",a:"TPMT deficiency = severe myelosuppression → azathioprine contraindicated.\nAzathioprine + allopurinol: reduce to ¼ dose (allopurinol inhibits xanthine oxidase).\nMonitoring: FBC + renal + LFTs every 2 wks until stable ×6 wks → monthly ×3 → 3-monthly.",hint:"¼ dose with allopurinol – the classic exam interaction.",tags:["azathioprine","TPMT","allopurinol","myelosuppression"]},
{t:"Mycophenolate – teratogenicity",top:"Immunosuppression",mod:"Oncology",q:"What are the key MHRA warnings for mycophenolate mofetil?",a:"Teratogenic: females need ≥1 contraceptive during + 6 weeks after (2 preferred). Males/female partners: during + 90 days after.\nSkin malignancies: avoid UV/sunlight.\nAlso: lymphomas, ILD (report SOB/cough), neutropenia, GI ulceration.",hint:"2 forms contraception for females, 90 days for males.",tags:["mycophenolate","teratogen","MHRA","contraception","ILD"]},
// ── ANTIMICROBIALS ───────────────────────────────────────
{t:"Most common pathogens",top:"Pathogens",mod:"Antimicrobials",q:"Name the most common pathogen for CAP, UTI, thrush, cellulitis, and meningitis.",a:"CAP: Streptococcus pneumoniae.\nUTI: Escherichia coli.\nThrush: Candida albicans.\nCellulitis: Staphylococcus aureus.\nMeningitis: Streptococcus pneumoniae.",hint:"Strep = lungs + meninges. Staph = skin. E. coli = urine.",tags:["pathogen","pneumonia","UTI","meningitis","cellulitis"]},
{t:"Antimicrobial stewardship – NICE",top:"Stewardship",mod:"Antimicrobials",q:"What are the 5 NICE antimicrobial stewardship principles?",a:"1. Don't start without clinical evidence of bacterial infection.\n2. Use local guidelines.\n3. Obtain cultures first – allows narrowing.\n4. Narrow spectrum preferred (C. diff/MRSA risk).\n5. Avoid widespread topical antibiotics.",hint:"Culture, narrow, don't guess.",tags:["stewardship","NICE","antibiotic","culture","narrow-spectrum"]},
{t:"Penicillin allergy – true vs non-true",top:"Penicillins",mod:"Antimicrobials",q:"What constitutes a true penicillin allergy?",a:"True allergy: immediate severe hypersensitivity – anaphylaxis, widespread rash, breathing difficulties, collapse. 1 in 100 patients have true allergy.\nNOT true: minor rash >72 hrs, or D+V.\nCross-reactivity: avoid if severe immediate hypersensitivity to any beta-lactam.",hint:"Minor rash or D+V ≠ true allergy.",tags:["penicillin","allergy","anaphylaxis","cross-reactivity"]},
{t:"Macrolides – CYP450 interactions",top:"Macrolides",mod:"Antimicrobials",q:"Which macrolides are CYP inhibitors and what are the clinical consequences?",a:"Clarithromycin and erythromycin are CYP inhibitors (not azithromycin).\n↑ levels of: warfarin, statins, rivaroxaban, CCBs, theophylline.\nStatins: stop during macrolide course.\nMacrolides also cause hypokalaemia and QT prolongation.",hint:"Clarithro + Erythro = CYP inhibitors. Azithromycin safer.",tags:["macrolide","clarithromycin","CYP","statin","QT"]},
{t:"Tetracyclines – milk interaction",top:"Tetracyclines",mod:"Antimicrobials",q:"Which tetracyclines CAN be taken with milk?",a:"Doxycycline, Lymecycline, Minocycline – 'Does Like Milk'.\nAll others: avoid milk, antacids, iron/zinc 2 hrs before or after.\nCI: <12 years, pregnancy/breastfeeding (teeth + skeletal development).",hint:"DLM = Does Like Milk.",tags:["tetracycline","doxycycline","milk","DLM","pregnancy"]},
{t:"Quinolones – MHRA warnings",top:"Quinolones",mod:"Antimicrobials",q:"What are the key MHRA warnings and contraindications for quinolones?",a:"MHRA: prescribe only when other antibiotics inappropriate.\nCI: pregnancy (arthropathy), breastfeeding, history of tendonitis.\nHigh tendon risk: >60 yrs, renal impairment, organ transplant, on corticosteroids.\nAlso: suicidal thoughts, QT prolongation, epilepsy (lowers seizure threshold).",hint:"Tendons + brain + QT – three organ systems quinolones damage.",tags:["quinolone","MHRA","tendonitis","QT","epilepsy"]},
{t:"Vancomycin – monitoring",top:"Glycopeptides",mod:"Antimicrobials",q:"How is vancomycin dosed and monitored?",a:"Dose based on total body weight; adjust to trough 15–20 mg/L.\nMeasure trough on day 2, immediately before next dose.\nToxicities: ototoxicity, nephrotoxicity.\nOtotoxicity interactions: cisplatin, loop diuretics, vinca alkaloids.",hint:"Trough 15–20 on day 2 before next dose.",tags:["vancomycin","trough","ototoxicity","nephrotoxicity"]},
{t:"Linezolid – key toxicities and interactions",top:"Linezolid",mod:"Antimicrobials",q:"What are the key toxicities of linezolid and its major interactions?",a:"Toxicities: peripheral/optic neuropathy (report tingling/visual changes), myelosuppression (FBC at baseline then weekly).\nLinezolid = weak MAOI: tyramine-rich foods → hypertensive crisis.\nSerotonin syndrome: SSRIs, TCAs, lithium, St John's Wort.",hint:"Treat linezolid like an MAOI – tyramine + serotonin syndrome risk.",tags:["linezolid","MAOI","tyramine","neuropathy","serotonin"]},
{t:"Clindamycin – C. difficile warning",top:"Clindamycin",mod:"Antimicrobials",q:"What is the key warning for clindamycin?",a:"C. difficile-associated diarrhoea (CDAD): can be fatal in elderly.\nMild to severe (peritonitis, shock, toxic megacolon).\nStop immediately if C. diff suspected or confirmed.\nAlso: SJS risk → discontinue.",hint:"Clindamycin = most notorious antibiotic for C. diff.",tags:["clindamycin","C.diff","CDAD","SJS"]},
{t:"Nitrofurantoin – key cautions",top:"Nitrofurantoin",mod:"Antimicrobials",q:"What are the key cautions and MHRA warning for nitrofurantoin?",a:"Avoid if eGFR <45 mL/min.\nAvoid at term in pregnancy (neonatal haemolysis).\nMHRA: pulmonary and hepatic events.\nTake with/after food. May discolour urine yellow-brown.",hint:"eGFR <45 = no nitrofurantoin. Not at term = haemolysis.",tags:["nitrofurantoin","eGFR","haemolysis","pregnancy","pulmonary"]},
{t:"Trimethoprim – key cautions",top:"Trimethoprim",mod:"Antimicrobials",q:"What are the key cautions and interactions for trimethoprim?",a:"Anti-folate: avoid 1st trimester + first weeks of life.\nCauses: hyperkalaemia, hyponatraemia, renal impairment, blood dyscrasias.\nInteractions: methotrexate + phenytoin (other anti-folates → toxicity).",hint:"Trimethoprim + methotrexate = double anti-folate → serious toxicity.",tags:["trimethoprim","anti-folate","methotrexate","hyperkalaemia"]},
{t:"Metronidazole – alcohol interaction",top:"Metronidazole",mod:"Antimicrobials",q:"What is the alcohol interaction with metronidazole?",a:"Must NOT drink alcohol during treatment.\nDisulfiram-like reaction: nausea, vomiting, stomach pain, hot flushes, palpitations.\nWait 48 hours AFTER finishing before drinking.\nSEs: metallic taste, nausea/D+V, take with/after food.",hint:"48 hours after metronidazole before alcohol.",tags:["metronidazole","alcohol","disulfiram","counselling"]},
{t:"Chloramphenicol – key warnings",top:"Chloramphenicol",mod:"Antimicrobials",q:"What are the key warnings for systemic and topical chloramphenicol?",a:"Systemic: avoid in pregnancy and breastfeeding (grey baby syndrome – cardiovascular collapse in neonates).\nBone marrow depression + hypersensitivity.\nOTC eye drops: not available for <2 years, pregnancy, or breastfeeding.",hint:"Grey baby syndrome = chloramphenicol + pregnancy.",tags:["chloramphenicol","grey-baby","pregnancy","bone-marrow"]},
{t:"TB treatment – RIPE phases",top:"TB",mod:"Antimicrobials",q:"What drugs are used in each phase of TB treatment and their specific toxicities?",a:"Initial 2 months: RIPE – Rifampicin, Isoniazid, Pyrazinamide, Ethambutol.\nContinuation 4 months: RI only.\nRifampicin: red fluids, CYP inducer. Isoniazid: peripheral neuropathy → pyridoxine (B6). Ethambutol: optic neuritis → check vision.",hint:"RIPE × 2 months, RI × 4 months. Red=rifampicin; B6=isoniazid; Eyes=ethambutol.",tags:["TB","RIPE","rifampicin","isoniazid","ethambutol"]},
{t:"Fungal infections – treatment by site",top:"Fungal Infections",mod:"Antimicrobials",q:"Match fungal infection sites to first-line treatments.",a:"Vaginal thrush: clotrimazole (topical) or fluconazole. Resistant: itraconazole.\nOral thrush: miconazole or nystatin.\nNail (onychomycosis): terbinafine or amorolfine nail lacquer ×1 year.\nTinea: topical antifungal or systemic itraconazole/terbinafine.",hint:"Clotrimazole/fluconazole for thrush. Terbinafine for nails.",tags:["antifungal","thrush","terbinafine","fluconazole","nail"]},
{t:"CAP – CURB65 and treatment",top:"Respiratory Infections",mod:"Antimicrobials",q:"What is CURB65 and what antibiotic is used at each severity level?",a:"CURB65: Confusion, Urea >7, RR ≥30, BP low, age ≥65.\nLow (0–1): amoxicillin. Moderate (2): amoxicillin ± clarithromycin. High (3–5): co-amoxiclav ± clarithromycin.\n2nd lines: doxycycline or levofloxacin.",hint:"Low = amoxicillin. High = co-amoxiclav. Add clarithromycin for atypicals.",tags:["CAP","CURB65","amoxicillin","clarithromycin","pneumonia"]},
{t:"UTI – treatment by patient group",top:"GU Infections",mod:"Antimicrobials",q:"What are first-line UTI antibiotics for non-pregnant women, pregnant women, and men?",a:"Non-pregnant women: nitrofurantoin or trimethoprim (3 days). 2nd: pivmecillinam or fosfomycin.\nPregnant: nitrofurantoin (NOT at term) or cefalexin/amoxicillin (7 days).\nMen: nitrofurantoin or trimethoprim (7 days).\nCI: nitrofurantoin if eGFR ≤45.",hint:"Pregnant + nitro = OK except at term.",tags:["UTI","nitrofurantoin","trimethoprim","pregnancy","cefalexin"]},
{t:"C. difficile treatment",top:"GI Infections",mod:"Antimicrobials",q:"How is C. difficile treated?",a:"1st line: oral vancomycin (10 days). 2nd: fidaxomicin. Life-threatening: vancomycin + IV metronidazole.\nOral vancomycin stays in gut (poor absorption).",hint:"C. diff = oral vancomycin. IV won't work for gut infection.",tags:["C.diff","vancomycin","fidaxomicin","metronidazole"]},
{t:"H. pylori – triple therapy",top:"GI Infections",mod:"Antimicrobials",q:"What is H. pylori triple therapy? What testing rules apply?",a:"PPI + 2 of: amoxicillin 1000 mg BD, clarithromycin 500 mg BD, metronidazole 400 mg BD.\nAmoxicillin standard unless penicillin allergy.\nStop PPI ≥2 weeks before testing; antibiotics ≥4 weeks.",hint:"Stop PPI 2 weeks, antibiotics 4 weeks before testing.",tags:["H.pylori","triple-therapy","PPI","amoxicillin"]},
{t:"Meningitis – antibiotic choice",top:"Blood Infections",mod:"Antimicrobials",q:"What antibiotics are used for suspected bacterial meningitis?",a:"Before hospital: ceftriaxone or benzylpenicillin.\nIn hospital: ceftriaxone or cefotaxime (unknown cause).\nListeria monocytogenes: amoxicillin (cephalosporins ineffective).",hint:"Listeria = amoxicillin – the one meningitis exception everyone forgets.",tags:["meningitis","ceftriaxone","Listeria","amoxicillin"]},
{t:"Cellulitis – antibiotic choice",top:"Skin Infections",mod:"Antimicrobials",q:"What is first-line treatment for cellulitis and how does location change choice?",a:"Standard: flucloxacillin. Penicillin allergy: clarithromycin (erythromycin in pregnancy) or doxycycline.\nNear eyes/nose: co-amoxiclav (penicillin allergy: clarithromycin + metronidazole).",hint:"Flucloxacillin standard. Facial = co-amoxiclav.",tags:["cellulitis","flucloxacillin","co-amoxiclav","facial"]},
{t:"STIs – first-line antibiotics",top:"GU Infections",mod:"Antimicrobials",q:"Give first-line antibiotic choices for chlamydia, gonorrhoea, and bacterial vaginosis.",a:"Chlamydia: 1st doxycycline, 2nd azithromycin.\nGonorrhoea: ceftriaxone or ciprofloxacin.\nBacterial vaginosis: oral or vaginal metronidazole.",hint:"Doxy for chlamydia; ceftriaxone for gonorrhoea; metro for BV.",tags:["STI","chlamydia","gonorrhoea","BV","doxycycline"]},
{t:"HIV – triple therapy drug classes",top:"Viral Infections",mod:"Antimicrobials",q:"Name the 5 HIV drug classes with one example each.",a:"NRTIs: tenofovir.\nNNRTIs: efavirenz.\nProtease inhibitors: ritonavir.\nIntegrase inhibitors: dolutegravir.\nEntry inhibitors: maraviroc.\nPEP: start within 72 hours, continue 28 days.",hint:"N-N-PI-II-EI. PEP = 72-hour window.",tags:["HIV","NRTI","NNRTI","dolutegravir","PEP"]},
{t:"Antibiotic food directions",top:"Antibiotic Extra Info",mod:"Antimicrobials",q:"Which antibiotics must be taken with food, on an empty stomach, or have no food restriction?",a:"WITH food: co-amoxiclav, doxycycline, metronidazole, nitrofurantoin, erythromycin, trimethoprim.\nEMPTY STOMACH (30–60 min before food): flucloxacillin, phenoxymethylpenicillin.\nNO RESTRICTION: amoxicillin, ciprofloxacin.",hint:"Flucloxacillin + phenoxymethylpenicillin = empty stomach. Often forgotten.",tags:["antibiotic","food","counselling","flucloxacillin","doxycycline"]},
{t:"Aminoglycosides – monitoring",top:"Aminoglycosides",mod:"Antimicrobials",q:"How are aminoglycosides monitored and what are their main toxicities?",a:"Measure peak (1 hr after dose) and trough (before next dose).\nGentamicin: check after 3–4 doses then every 3 days.\nMultiple daily: peak 5–10 mg/L (endo: 3–5); trough <2 mg/L (endo: <1).\nToxicities: ototoxicity (MHRA), nephrotoxicity.\nCI: pregnancy, myasthenia gravis.",hint:"Peak = dose; trough = interval. Loop diuretics + aminoglycosides = ototoxicity.",tags:["aminoglycoside","gentamicin","ototoxicity","nephrotoxicity","monitoring"]},
// ── MSK & PAIN ───────────────────────────────────────────
{t:"NSAIDs – side-effects mnemonic",top:"Pain & NSAIDs",mod:"MSK & Pain",q:"List the 6 main NSAID side-effects using the mnemonic.",a:"GI events (use PPI), Cardiovascular events, Nephrotoxicity, Bleeding, Bronchospasm, Fluid retention.\nMnemonic: GOOD CHEMISTS NEED BIG BRIGHT FERRARIS.",hint:"GCNBBF. Avoid in severe heart failure, renal impairment <30, after 20 wks pregnancy.",tags:["NSAID","side-effects","GI","nephrotoxicity","bronchospasm"]},
{t:"Rheumatoid arthritis – DMARD ladder",top:"Arthritis",mod:"MSK & Pain",q:"Outline the pharmacological treatment ladder for rheumatoid arthritis.",a:"Symptom control: glucocorticoids (flares) + NSAIDs + PPI.\n1st DMARD: methotrexate, leflunomide, or sulfasalazine.\nBridge with corticosteroids when starting DMARD.\n2nd: combination DMARD.\n3rd: biologics (adalimumab, infliximab, rituximab, tocilizumab, baricitinib).",hint:"MTX first. Biologics third. Bridge with steroids.",tags:["RA","DMARD","methotrexate","biologic","adalimumab"]},
{t:"Methotrexate – dosing and monitoring",top:"Arthritis",mod:"MSK & Pain",q:"What are the key prescribing rules, monitoring and antidote for methotrexate?",a:"Once WEEKLY – specify day. Take folic acid 5 mg on a DIFFERENT day.\nMonitoring: FBC + renal + LFTs every 2 wks until stable ×6 wks → monthly ×3 → every 3 months.\nMHRA: photosensitivity.\nAntidote: folinic acid (calcium folinate).",hint:"ONCE WEEKLY – the most dangerous prescribing error.",tags:["methotrexate","weekly","folic-acid","folinic-acid","monitoring"]},
{t:"Gout – acute vs chronic management",top:"Gout",mod:"MSK & Pain",q:"How is an acute gout flare managed and what is used for long-term urate lowering?",a:"Acute: NSAID (not aspirin) until 1–2 days after flare ends. Or colchicine 500 mcg 2–4× (max 3 days, no repeat within 3 days). Or oral corticosteroid 3–5 days.\nChronic: allopurinol or febuxostat (continue during acute flare).",hint:"Colchicine: 3-day max, 3-day gap. Allopurinol: screen HLA-B*5801 in Han Chinese/Thai/Korean.",tags:["gout","colchicine","allopurinol","febuxostat","urate"]},
{t:"Allopurinol and febuxostat – interactions",top:"Gout",mod:"MSK & Pain",q:"What is the critical interaction for both allopurinol and febuxostat?",a:"Both + azathioprine: inhibit xanthine oxidase → toxicity.\nAllopurinol: reduce azathioprine to 25% of standard.\nFebuxostat: reduce azathioprine to 20%.\nFebuxostat MHRA: caution in major CVD.",hint:"¼ dose azathioprine with allopurinol. 1/5 with febuxostat.",tags:["allopurinol","febuxostat","azathioprine","xanthine-oxidase","gout"]},
{t:"Anaphylaxis – management",top:"Allergy & Anaphylaxis",mod:"MSK & Pain",q:"Outline anaphylaxis management including adrenaline doses.",a:"IM adrenaline immediately. Call 999. Lie flat, raise legs. Remove trigger.\nRepeat after 5–15 min if no improvement.\nHospital: O2 (SpO2 94–98%), IV fluids if hypotension.\nDoses: <6 months = 100–150 mcg; 6 months–6 yrs = 150 mcg; 6–12 yrs = 300 mcg; ≥12 yrs = 500 mcg.\nMHRA: prescribe 2 auto-injectors at all times.",hint:"Age ≥12 = 500 mcg. Always 2 auto-injectors. IM not IV.",tags:["anaphylaxis","adrenaline","auto-injector","MHRA"]},
{t:"Antihistamines – generations and pregnancy",top:"Allergy & Anaphylaxis",mod:"MSK & Pain",q:"Which antihistamines are safe in pregnancy and breastfeeding?",a:"1st generation (sedating): chlorphenamine, promethazine, cyclizine.\n2nd generation (less sedating): cetirizine, loratadine, fexofenadine.\nPregnancy: avoid if possible; loratadine if needed.\nBreastfeeding: loratadine or cetirizine.\nCetirizine CI: eGFR <10.",hint:"Loratadine = safest for pregnancy.",tags:["antihistamine","pregnancy","loratadine","cetirizine","sedating"]},
// ── RESPIRATORY ──────────────────────────────────────────
{t:"Asthma – chronic treatment steps (≥12 yrs)",top:"Asthma",mod:"Respiratory",q:"Outline stepwise chronic asthma treatment under updated NICE guidance.",a:"Step 1: Low-dose ICS/formoterol (AIR = budesonide/formoterol) as needed – no SABA without ICS.\nStep 2: AIR as MART (≥3 reliever days/wk or ≥1 night waking/wk).\nStep 3: Moderate-dose MART.\nStep 4: FeNO + eosinophils. Raised → refer. Not raised → add LTRA or LAMA.\nStep 5: Refer to specialist.",hint:"AIR = budesonide/formoterol MART. No SABA alone. FeNO at step 4.",tags:["asthma","MART","ICS","formoterol","NICE"]},
{t:"Acute asthma – management",top:"Asthma",mod:"Respiratory",q:"How is moderate vs severe acute asthma managed?",a:"Moderate: SABA 1 puff every 30–60 sec via spacer (max 10 puffs). Prednisolone 40–50 mg × 5 days (adults).\nSevere/life-threatening: salbutamol 5 mg via O2-driven nebuliser. Add ipratropium. Consider IV magnesium/aminophylline.",hint:"Moderate = spacer. Severe = nebuliser + ipratropium.",tags:["acute-asthma","salbutamol","nebuliser","ipratropium","prednisolone"]},
{t:"COPD – rescue pack",top:"COPD",mod:"Respiratory",q:"How are COPD exacerbations managed with a rescue pack?",a:"Prednisolone 30 mg × 5 days + antibiotic (amoxicillin, doxycycline, or clarithromycin) × 5 days.\nAdd theophylline if nebulisers inadequate. O2 if saturations low.",hint:"30 mg pred × 5 + antibiotic × 5 = standard rescue pack.",tags:["COPD","exacerbation","rescue-pack","prednisolone","antibiotic"]},
{t:"Inhaled corticosteroids – counselling",top:"Inhalation Therapies",mod:"Respiratory",q:"Name 4 key counselling points for inhaled corticosteroids.",a:"Rinse mouth with water after use (candidiasis + hoarseness).\nUse a spacer (reduces oropharyngeal deposition).\nBeclomethasone: prescribe by brand (Qvar/Fostair = 2× stronger).\nSteroid card if prolonged high dose. Monitor height in children.",hint:"Rinse, spacer, brand for beclomethasone, steroid card.",tags:["ICS","candidiasis","beclomethasone","brand","spacer"]},
{t:"Beta-2 agonists – side-effects",top:"Inhalation Therapies",mod:"Respiratory",q:"What are the side-effects and key cautions for beta-2 agonists?",a:"SEs: arrhythmias/palpitations, tremor, hyperglycaemia, headache.\nCautions: hyperthyroidism, diabetes (DKA risk IV), hypokalaemia.\nInteractions: hypokalaemia (theophylline, corticosteroids, loop/thiazide diuretics). ↑ digoxin toxicity.\nNever prescribe SABA without ICS.",hint:"SABA + theophylline + steroids + diuretics = triple hypokalaemia risk.",tags:["SABA","beta-2","hypokalaemia","tremor","ICS"]},
{t:"Theophylline – therapeutic range",top:"Inhalation Therapies",mod:"Respiratory",q:"What is theophylline's therapeutic range and how is it monitored?",a:"Therapeutic range: 10–20 mg/L.\nSample 4–6 hours after dose. Check at day 5 and ≥3 days after dose change.\nPrescribe by brand (bioavailability varies).\nSmoking ↑ clearance → dose adjustment needed if stopping.\nToxicity: vomiting, tremor, palpitations, arrhythmias.",hint:"4–6 hr sample, brand only, smoking changes metabolism.",tags:["theophylline","therapeutic-range","brand","smoking","monitoring"]},
{t:"Montelukast – MHRA warning",top:"Inhalation Therapies",mod:"Respiratory",q:"What is the MHRA warning for montelukast?",a:"Risk of neuropsychiatric reactions.\nStop if: insomnia, mood changes, anxiety, depression, behavioural changes.\nChurg-Strauss syndrome: report eosinophilia, vasculitic rash, worsening pulmonary symptoms.\nTaken in the evenings.",hint:"Montelukast = mental health warning. Evening dosing.",tags:["montelukast","neuropsychiatric","Churg-Strauss","MHRA"]},
{t:"Inhaler devices – technique",top:"Inhalation Therapies",mod:"Respiratory",q:"What inhalation technique is required for pMDI vs DPI?",a:"pMDI: SLOW AND STEADY. Devices: Aerosol, Autohaler, Evohaler.\nDPI: FAST AND DEEP. Devices: Accuhaler, Turbohaler, Ellipta, Spiromax.\nSpacers: slow and steady. Wash with detergent, air dry, replace every 12 months.",hint:"pMDI = slow; DPI = fast. Spacer every 12 months.",tags:["inhaler","pMDI","DPI","technique","spacer"]},
{t:"Croup – treatment by severity",top:"Croup",mod:"Respiratory",q:"How is croup treated by severity?",a:"Mild: single oral dexamethasone dose (manage at home).\nModerate/severe: hospital + oral dexamethasone.\nCan't take oral: IM dexamethasone or nebulised budesonide.\nImpending respiratory failure: + oxygen.",hint:"Dexamethasone for all croup. Nebulised budesonide if oral impossible.",tags:["croup","dexamethasone","budesonide","paediatric"]},
{t:"Cystic fibrosis – treatment overview",top:"Cystic Fibrosis",mod:"Respiratory",q:"What are the 5 main pharmacological treatment areas in cystic fibrosis?",a:"1. Mucoactive: dornase alfa.\n2. CFTR modulators: ivacaftor/tezacaftor/elexacaftor combination.\n3. Pulmonary infection: flucloxacillin (Staph aureus).\n4. Immunomodulatory: long-term azithromycin.\n5. Exocrine pancreatic insufficiency: pancreatin.",hint:"D-CFTR-F-A-P mnemonic.",tags:["cystic-fibrosis","CFTR","dornase","ivacaftor","pancreatin"]},
// ── DERM & EYE ───────────────────────────────────────────
{t:"Eczema – treatment by severity",top:"Eczema/Dermatitis",mod:"Derm & Eye",q:"Outline treatment of atopic eczema by severity and the facial steroid rule.",a:"Mild: emollients + hydrocortisone 1% (face always OK).\nModerate: moderate steroid (betamethasone valerate 0.025% or clobetasone 0.05%). Face: hydrocortisone 1%.\nSevere: potent steroid (betamethasone 0.1%). Face: moderate steroid. Oral prednisolone 30 mg × 1 wk for acute flares.\nInfected: flucloxacillin (clarithromycin if pen allergy).",hint:"Face = always one potency weaker than body.",tags:["eczema","topical-steroid","emollient","face","flucloxacillin"]},
{t:"Psoriasis – treatment options",top:"Psoriasis",mod:"Derm & Eye",q:"List pharmacological treatments for psoriasis from topical to systemic.",a:"Topical: emollients, corticosteroid + vitamin D analogue, coal tar, salicylic acid, dithranol.\nSpecialist: calcineurin inhibitors (tacrolimus/pimecrolimus), narrow-band UVB phototherapy.\nSystemic: methotrexate, ciclosporin, acitretin, TNF-alpha inhibitors, monoclonal antibodies.",hint:"ICS + Vitamin D = core topical combo. UVB preferred phototherapy.",tags:["psoriasis","vitamin-D","methotrexate","TNF","UVB"]},
{t:"Glaucoma – treatment ladder",top:"Glaucoma",mod:"Derm & Eye",q:"Outline the pharmacological treatment ladder for primary open-angle glaucoma.",a:"1st: topical prostaglandin analogue (latanoprost, travoprost, bimatoprost, tafluprost).\n2nd: topical beta-blocker (timolol, betaxolol).\n3rd: topical carbonic anhydrase inhibitor (brinzolamide, dorzolamide), pilocarpine, or brimonidine.",hint:"PBA – Prostaglandin, Beta-blocker, everything else.",tags:["glaucoma","prostaglandin","timolol","pilocarpine","IOP"]},
{t:"Prostaglandin eye drops – side-effects",top:"Glaucoma",mod:"Derm & Eye",q:"Name 5 side-effects of prostaglandin analogue eye drops.",a:"Brown iris pigmentation (irreversible, treated eye only). Eyelash darkening/thickening/lengthening. Periocular skin pigmentation. Blepharitis. Dry eyes and ocular irritation.\nAvoid in pregnancy/breastfeeding.",hint:"Brown iris + longer lashes = notable prostaglandin effects.",tags:["prostaglandin","eye-drops","iris-pigmentation","glaucoma"]},
{t:"Eye drops – administration rules",top:"Glaucoma",mod:"Derm & Eye",q:"What are the key administration rules for multiple eye drops?",a:"≥5 minutes between each eye drop. Eye ointment applied last.\nContact lenses: remove before, reinsert after 15 minutes.\nPilocarpine: not with soft contact lenses.\nTopical beta-blockers: systemic absorption can occur.",hint:"5 minutes between drops, ointment last, contacts out 15 min.",tags:["eye-drops","contact-lenses","pilocarpine","timing"]},
{t:"Head lice – treatment options",top:"Head Lice",mod:"Derm & Eye",q:"What are first-line head lice treatments and who should avoid chemical insecticides?",a:"Preferred for pregnant/breastfeeding, <2 yrs, asthma, eczema: wet combing (days 1,5,9,13) OR dimeticone 4% lotion ×8 hrs, repeat day 7.\nChemical: malathion 0.5% ×12 hrs, repeat day 7. Avoid in above groups.\nMHRA: serious burns risk near open flames.",hint:"Asthma/eczema/pregnancy = wet combing or dimeticone. Malathion = avoid.",tags:["head-lice","dimeticone","malathion","wet-combing","MHRA"]},
{t:"Melanoma – ABCDE recognition",top:"Melanoma",mod:"Derm & Eye",q:"What mole features should prompt urgent referral?",a:"Asymmetrical. Border uneven. Colours mixed. Diameter >6 mm. Evolving (changing size/shape/colour).\nAlso: swollen, sore, bleeding, itchy, or crusty.\nUrgent 2-week wait referral. Main cause: UV light. Main treatment: surgery.",hint:"ABCDE: Asymmetry, Border, Colour, Diameter >6mm, Evolving.",tags:["melanoma","ABCDE","referral","skin","UV"]},
{t:"Alopecia – treatment options",top:"Hair Conditions",mod:"Derm & Eye",q:"What treatments are used for alopecia areata vs androgenetic alopecia?",a:"Alopecia areata: potent/very potent corticosteroid ×3 months or minoxidil.\nAndrogenetic: topical minoxidil or oral finasteride 1 mg.\nHirsutism: topical eflornithine, COC (ethinylestradiol-containing), hair removal.",hint:"Minoxidil = both types. Finasteride = androgenetic only.",tags:["alopecia","minoxidil","finasteride","androgenetic","hirsutism"]},
// ── VACCINES ─────────────────────────────────────────────
{t:"Vaccine types – examples",top:"Vaccines",mod:"Vaccines & Immunology",q:"Classify vaccines into 5 types and give examples.",a:"Inactivated: polio, influenza, hepatitis A.\nLive attenuated: MMR, yellow fever, rotavirus.\nToxoids: tetanus, diphtheria.\nViral vectors: COVID-19 AstraZeneca.\nmRNA: COVID-19 Pfizer, Moderna.",hint:"Live = CI in pregnancy and immunosuppressed. Toxoids = tetanus/diphtheria.",tags:["vaccine","live","inactivated","mRNA","toxoid"]},
{t:"Live vaccine intervals",top:"Vaccines",mod:"Vaccines & Immunology",q:"What interval rules apply between live vaccines?",a:"≥4 weeks between repeat doses of same live vaccine.\nYellow fever + MMR: ≥4 weeks, cannot give same day.\nVaricella + MMR: ≥4 weeks but CAN give same day.",hint:"Yellow fever + MMR = 4 weeks + NOT same day. Varicella + MMR = same day OK.",tags:["vaccine","live","MMR","yellow-fever","varicella"]},
{t:"UK childhood vaccine schedule",top:"Vaccines",mod:"Vaccines & Immunology",q:"What vaccines are given at 8 weeks, 12 weeks, 16 weeks, and 1 year?",a:"8 wks: 6-in-1 (DTP-Polio-Hib-HepB) + MenB + Rotavirus.\n12 wks: 6-in-1 + MenB + Rotavirus.\n16 wks: 6-in-1 + Pneumococcal.\n1 yr: MMR + MenB + Pneumococcal.\n14 yrs: Td/Polio + MenACWY.\n12–13 yrs: HPV.",hint:"8-12-16 = 6-in-1 series. 1 year = MMR arrives.",tags:["vaccine","schedule","childhood","MMR","6-in-1"]},
{t:"Adult vaccines by age",top:"Vaccines",mod:"Vaccines & Immunology",q:"What vaccines are offered at age 65, 70–79, and 75 years?",a:"65 years: pneumococcal (one-off) + shingles + annual influenza (from September).\n70–79 years: shingles.\n75 years: RSV.",hint:"65 = PSI (Pneumo, Shingles, Influenza). 75 = RSV.",tags:["vaccine","adult","shingles","pneumococcal","RSV"]},
// ── PHARMACY LAW ─────────────────────────────────────────
{t:"Controlled drug schedules",top:"CD Schedules",mod:"Pharmacy Law",q:"Give 2–3 examples of drugs in each CD schedule (1–5).",a:"Sched 1 (no therapeutic use): cannabis, LSD, MDMA.\nSched 2: morphine, diamorphine, fentanyl, oxycodone, methadone, methylphenidate.\nSched 3: buprenorphine, tramadol, pregabalin, gabapentin, midazolam, temazepam.\nSched 4 Part 1: benzodiazepines, z-hypnotics, Sativex.\nSched 4 Part 2: anabolic steroids.\nSched 5: codeine, dihydrocodeine, nitrous oxide.",hint:"Sched 2 = opioids. Sched 3 = buprenorphine + tramadol + pregabalin/gabapentin.",tags:["CD","schedule","controlled-drug","morphine","buprenorphine"]},
{t:"Prescription legal requirements",top:"Prescription Requirements",mod:"Pharmacy Law",q:"What are the legal requirements for a valid prescription?",a:"Prescriber signature. Prescriber address + type. Patient name and address. Patient age if under 12. Date (valid 6 months; 28 days for Sched 1–4 CDs).\nClinical: drug name, form, strength, dose/frequency, duration, quantity.\nFaxed prescriptions: not legitimate. Dispensing Sched 2/3 from fax = criminal offence.",hint:"Age only required if <12. Faxed Sched 2/3 = criminal offence.",tags:["prescription","legal","fax","age","CD"]},
{t:"Instalment prescriptions – key rules",top:"Instalment Prescriptions",mod:"Pharmacy Law",q:"What are the key rules for dispensing instalment prescriptions?",a:"Form: FP10MDA/WP10MDA. Max 14-day treatment period. First instalment within 28 days of date.\nSpecify: amount and interval.\n3+ consecutive missed doses: do not dispense, contact prescriber.\nSupervision: not a legal requirement even if stated.",hint:"3 missed doses = stop and call prescriber.",tags:["instalment","FP10MDA","missed-dose","CD","supervision"]},
{t:"Emergency supply rules",top:"Emergency Supply",mod:"Pharmacy Law",q:"What are the supply limits for emergency supply by a pharmacist?",a:"Sched 1, 2, or 3: NOT allowed. Exception: phenobarbital for epilepsy (5 days max).\nSched 4 or 5: 5 days max.\nAll other POMs: 30 days max.\nInsulin/aerosol/cream/ointment: smallest pack size.\nOral contraceptive: one full treatment cycle.\nLabel: 'Emergency Supply'. Prescriber request: prescription within 72 hours.",hint:"Sched 1-3 = no supply (except phenobarb). POMs = 30 days.",tags:["emergency-supply","POM","phenobarbital","72-hours","OC"]},
{t:"CD record keeping",top:"Record Keeping",mod:"Pharmacy Law",q:"Which CDs require register entries and what must be recorded?",a:"Schedule 1 and 2 (also Sativex). Entries in chronological order, same day or next if impractical.\nNo alterations – corrections in margin/foot with pharmacist details + date.\nObtained: date, supplier name/address, quantity.\nSupplied: date, recipient name/address, prescriber details, quantity, collector identity.",hint:"Sched 1 + 2 = register. No white-out – margin corrections only.",tags:["CD","register","record-keeping","Sativex","no-alterations"]},
{t:"CD destruction rules",top:"CD Destruction",mod:"Pharmacy Law",q:"What are the rules for destroying controlled drugs?",a:"Schedules 2, 3, and 4 (Part 1) must be denatured.\nSchedule 2: must be witnessed by authorised accountable officer.\nPatient returns: no authorised witness needed but witness by colleague + log in CD Patient Returns Book.",hint:"Sched 2 = accountable officer witness. Returns = colleague witness + log.",tags:["CD","destruction","denaturing","accountable-officer","returns"]},
{t:"CD requisition forms",top:"CD Requisitions",mod:"Pharmacy Law",q:"What must a CD requisition form contain and what form is used?",a:"Form: FP10CDF (from NHSBSA website). Applies to Sched 1, 2, and 3.\nMust include: drug name, strength, form, quantity and unit. Purpose. Requester's name, occupation, qualifications, work address. Signature.",hint:"FP10CDF for CD requisitions. Name + purpose + address + signature.",tags:["CD","requisition","FP10CDF","NHSBSA"]},
{t:"Labelling requirements",top:"Labelling",mod:"Pharmacy Law",q:"What information must appear on a dispensed medicine label?",a:"Patient name. Pharmacy name and address. Date of supply. Medication name. Directions for use. Precautions (including 'Keep out of the reach and sight of children').",hint:"Patient, Pharmacy, Date, Drug, Directions, Precautions – 6 label elements.",tags:["labelling","dispensing","legal","precautions"]},
{t:"Drugs and driving – legal limits",top:"Drugs & Driving",mod:"Pharmacy Law",q:"Distinguish Group 1 (low limit) and Group 2 (higher limit) drugs in driving legislation.",a:"Group 1 (illegal drugs): cannabis, cocaine, MDMA, LSD, ketamine, heroin.\nGroup 2 (medicinal): amphetamine, methadone, morphine, codeine, tramadol, benzodiazepines (COLD FeeT).\nStatutory medical defence: legitimately prescribed + not impaired = protection.",hint:"COLD FeeT benzos = Group 2. Statutory defence only if prescribed AND not impaired.",tags:["driving","legal-limit","COLD-FeeT","statutory-defence","CD"]},
{t:"EEA/Switzerland prescriptions",top:"EEA Prescriptions",mod:"Pharmacy Law",q:"What rules apply when dispensing an EEA/Switzerland prescription?",a:"UK medicines only. Must contain: prescriber address, type and signature; patient name; date (6 months validity; 28 days Sched 4).\nCannot dispense Sched 1–3 – refer to UK prescriber.\nDispense as private prescription.",hint:"EEA = private prescription. No Sched 1-3 at all.",tags:["EEA","prescription","private","CD","international"]},
];
